// §3.18 ML-DSA C++ wrapper (determ::c99::mldsa) self-test — kept in its OWN
// function so the heavy Sign_internal/Verify_internal stack frames (~170 KB each)
// don't stack on top of the large test-c99-api frame and trip the stack guard
// (0xC0000409). Returns true iff every wrapper round-trip holds.
static bool mldsa_api_selftest() {
    using namespace determ::c99;
    using namespace determ::c99::mldsa;
    try {
        int si = 0;
        for (ParamSet ps : {ParamSet::ML_DSA_44, ParamSet::ML_DSA_65, ParamSet::ML_DSA_87}) {
            std::array<uint8_t,32> seed{}; for (int i=0;i<32;i++) seed[i]=(uint8_t)(si*31+i+1);
            KeyPair kp = keygen(ps, seed);
            if (kp.pk.size()!=pk_bytes(ps) || kp.sk.size()!=sk_bytes(ps)) return false;
            const determ_mldsa_params& p = params(ps);       // wrapper keygen == raw C keygen
            std::vector<uint8_t> rpk(determ_mldsa_pk_bytes(&p)), rsk(determ_mldsa_sk_bytes(&p));
            determ_mldsa_keygen(&p, seed.data(), rpk.data(), rsk.data());
            if (kp.pk != rpk || kp.sk != rsk) return false;
            std::array<uint8_t,3> ctx{'c','t','x'};
            std::string m = "determ ml-dsa sign roundtrip";
            Bytes mp = format_message(ctx, std::span<const uint8_t>((const uint8_t*)m.data(), m.size()));
            Bytes sig = sign(ps, kp.sk, mp);                 // deterministic
            if (!verify(ps, kp.pk, mp, sig)) return false;    // accepts
            if (sign(ps, kp.sk, mp) != sig) return false;     // deterministic
            Bytes bad = sig; bad[bad.size()/3] ^= 0x01;
            if (verify(ps, kp.pk, mp, bad)) return false;     // tampered sig rejects
            bad.pop_back();
            if (verify(ps, kp.pk, mp, bad)) return false;     // short sig rejects safely
            si++;
        }
        return true;
    } catch (const std::exception& e) {
        std::cerr << "  mldsa_api_selftest exception: " << e.what() << "\n";
        return false;
    }
}

// ─── Commands ────────────────────────────────────────────────────────────────

static int cmd_init(int argc, char** argv) {
    std::string data_dir     = default_data_dir();
    std::string profile      = "web";
    std::string genesis_path = "";
    for (int i = 0; i < argc - 1; ++i) {
        if (std::string(argv[i]) == "--data-dir") data_dir     = argv[i + 1];
        if (std::string(argv[i]) == "--profile")  profile      = argv[i + 1];
        if (std::string(argv[i]) == "--genesis")  genesis_path = argv[i + 1];
    }

    fs::create_directories(data_dir);
    std::string kpath = data_dir + "/node_key.json";
    std::string cpath = config_path(data_dir);
    std::string chain_path = data_dir + "/chain.json";

    if (fs::exists(kpath)) {
        std::cout << "Key already exists at " << kpath << " (skipping keygen)\n";
    } else {
        auto key = crypto::generate_node_key();
        crypto::save_node_key(key, kpath);
        std::cout << "Generated node key: pubkey=" << to_hex(key.pub) << "\n";
    }

    node::Config cfg;
    cfg.data_dir   = data_dir;
    cfg.key_path   = kpath;
    cfg.chain_path = chain_path;
    cfg.listen_port = 7777;
    cfg.rpc_port    = 7778;

    chain::TimingProfile tp = chain::PROFILE_WEB;
    if      (profile == "cluster")        tp = chain::PROFILE_CLUSTER;
    else if (profile == "regional")       tp = chain::PROFILE_REGIONAL;
    else if (profile == "global")         tp = chain::PROFILE_GLOBAL;
    else if (profile == "tactical")       tp = chain::PROFILE_TACTICAL;
    else if (profile == "single_test")    tp = chain::PROFILE_SINGLE_TEST;
    else if (profile == "cluster_test")   tp = chain::PROFILE_CLUSTER_TEST;
    else if (profile == "web_test")       tp = chain::PROFILE_WEB_TEST;
    else if (profile == "regional_test")  tp = chain::PROFILE_REGIONAL_TEST;
    else if (profile == "global_test")    tp = chain::PROFILE_GLOBAL_TEST;
    else if (profile == "tactical_test")  tp = chain::PROFILE_TACTICAL_TEST;
    else if (profile != "web") {
        std::cerr << "Unknown --profile " << profile
                  << " (expected: cluster|web|regional|global|tactical|"
                  << "single_test|cluster_test|web_test|regional_test|global_test|tactical_test)\n";
        return 1;
    }
    cfg.tx_commit_ms   = tp.tx_commit_ms;
    cfg.block_sig_ms   = tp.block_sig_ms;
    cfg.abort_claim_ms = tp.abort_claim_ms;
    cfg.m_creators     = tp.m_creators;
    cfg.k_block_sigs   = tp.k_block_sigs;
    // A6: pin chain_role + sharding_mode from the chosen profile so
    // cmd_start can hand them to the validator without re-resolving the
    // profile. Genesis remains the source of truth at runtime — Node's
    // ctor cross-checks gcfg.chain_role against cfg_.chain_role and
    // gates loadtime on cfg_.sharding_mode (see node.cpp).
    cfg.chain_role     = tp.chain_role;
    cfg.sharding_mode  = tp.sharding_mode;

    if (!genesis_path.empty()) {
        cfg.genesis_path = genesis_path;
        try {
            auto gcfg = chain::GenesisConfig::load(genesis_path);
            cfg.genesis_hash = to_hex(chain::compute_genesis_hash(gcfg));
            std::cout << "Pinned genesis hash: " << cfg.genesis_hash << "\n";
        } catch (std::exception& e) {
            std::cerr << "Warning: could not load genesis at " << genesis_path
                      << " (" << e.what() << "); pin left empty\n";
        }
    }

    cfg.save(cpath);

    const char* mode = (cfg.k_block_sigs == cfg.m_creators) ? "strong" : "weak";
    std::cout << "Config written to " << cpath
              << " (profile: " << profile
              << ", M=" << cfg.m_creators
              << ", K=" << cfg.k_block_sigs
              << ", mode=" << mode << ")\n";
    std::cout << "Edit the config to set your domain and bootstrap peers, then run:\n";
    std::cout << "  determ start\n";
    return 0;
}

static int cmd_start(int argc, char** argv) {
    std::string data_dir = default_data_dir();
    std::string cfg_path;
    // S-046: strict argv. cmd_start historically parsed only --config /
    // --data-dir and SILENTLY IGNORED everything else — so a caller passing
    // e.g. --listen-port/--rpc-port/--genesis/--peer "started" a node with
    // none of those settings applied (init-default ports, no genesis), which
    // is exactly how a broken test recipe shipped unnoticed. A node launcher
    // must fail closed on arguments it does not understand.
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--config" && i + 1 < argc)        { cfg_path = argv[++i]; }
        else if (a == "--data-dir" && i + 1 < argc) { data_dir = argv[++i]; }
        else {
            std::cerr << "start: unknown argument '" << a << "'\n"
                      << "  determ start accepts ONLY --config <file> and "
                         "--data-dir <dir>.\n"
                      << "  Per-node settings (ports, peers, genesis pin, "
                         "timers) live in config.json.\n";
            return 1;
        }
    }
    if (cfg_path.empty()) cfg_path = config_path(data_dir);

    try {
        auto cfg = node::Config::load(cfg_path);

        if (cfg.key_path.empty()) cfg.key_path = cfg.data_dir + "/node_key.json";
        if (!fs::exists(cfg.key_path)) {
            auto key = crypto::generate_node_key();
            crypto::save_node_key(key, cfg.key_path);
            std::cout << "[init] Generated node key\n" << std::flush;
        }
        if (cfg.chain_path.empty()) cfg.chain_path = cfg.data_dir + "/chain.json";

        std::cout << "[determ] Loading node domain=" << cfg.domain
                  << " genesis_path=" << cfg.genesis_path << "\n" << std::flush;

        node::Node node(cfg);

        rpc::RpcServer rpc_server(node.transport_access(), node.event_loop_access(),
                                       node, cfg.rpc_port, cfg.rpc_localhost_only,
                                       cfg.rpc_auth_secret,
                                       cfg.rpc_rate_per_sec,
                                       cfg.rpc_rate_burst);
        rpc_server.start();

        std::cout << "[determ] Starting node domain=" << cfg.domain
                  << " port=" << cfg.listen_port << "\n" << std::flush;
        node.run(); // blocks
        return 0;
    } catch (std::exception& e) {
        std::cerr << "[determ] FATAL: " << e.what() << std::endl;
        std::cerr.flush();
        return 1;
    } catch (...) {
        std::cerr << "[determ] FATAL: unknown exception" << std::endl;
        std::cerr.flush();
        return 1;
    }
}

// Guarded CLI integer-argument parses. A bare std::sto* throws
// std::invalid_argument out of main on a non-numeric value ->
// std::terminate -> process abort (fail-open crash). Each prints
// "<cmd>: <flag> must be an integer" and returns false so the caller
// can `return 1`. Per-type to preserve range (e.g. amounts/fees need
// full u64 via stoull). Plain std::sto* (no width check) to match the
// wallet's guarded sites.
static bool arg_i32(const char* cmd, const char* flag, const char* v, int& out) {
    try { out = std::stoi(v); return true; }
    catch (...) { std::cerr << cmd << ": " << flag << " must be an integer\n"; return false; }
}
static bool arg_u32(const char* cmd, const char* flag, const char* v, uint32_t& out) {
    try { out = static_cast<uint32_t>(std::stoul(v)); return true; }
    catch (...) { std::cerr << cmd << ": " << flag << " must be an integer\n"; return false; }
}
static bool arg_i64(const char* cmd, const char* flag, const char* v, int64_t& out) {
    try { out = static_cast<int64_t>(std::stoll(v)); return true; }
    catch (...) { std::cerr << cmd << ": " << flag << " must be an integer\n"; return false; }
}
static bool arg_u64(const char* cmd, const char* flag, const char* v, uint64_t& out) {
    try { out = static_cast<uint64_t>(std::stoull(v)); return true; }
    catch (...) { std::cerr << cmd << ": " << flag << " must be an integer\n"; return false; }
}

static uint16_t get_rpc_port(int argc, char** argv) {
    for (int i = 0; i < argc - 1; ++i)
        if (std::string(argv[i]) == "--rpc-port") {
            try {
                return static_cast<uint16_t>(std::stoi(argv[i + 1]));
            } catch (...) {
                std::cerr << "determ: --rpc-port must be an integer\n";
                std::exit(1);
            }
        }
    return 7778;
}

// Bounded auto-retry for tx submissions: re-resolves nonce on each attempt,
// returns the last response or an error after `max_retries` failures.
// "Failure" here means the RPC raised a nonce-mismatch error or returned a
// queued tx that still hadn't been included after `retry_window_blocks`
// of polling. The retry_window check is cheap (status RPC).
static int submit_tx_with_retry(uint16_t port,
                                 const std::string& method,
                                 nlohmann::json params,
                                 int max_retries = 3) {
    for (int attempt = 0; attempt < max_retries; ++attempt) {
        try {
            auto result = rpc::rpc_call("127.0.0.1", port, method, params);
            std::cout << result.dump(2) << "\n";
            return 0;
        } catch (std::exception& e) {
            std::string msg = e.what();
            // Re-attempt only on transient nonce-mismatch errors. Other errors
            // are non-retryable.
            if (msg.find("nonce") == std::string::npos || attempt + 1 == max_retries) {
                std::cerr << "Error: " << msg << "\n";
                return 1;
            }
            std::cerr << "[retry " << (attempt + 1) << "] " << msg << "\n";
        }
    }
    return 1;
}

static int cmd_register(int argc, char** argv) {
    if (argc < 1) { std::cerr << "Usage: determ register <domain>\n"; return 1; }
    std::string domain   = argv[0];
    uint16_t    rpc_port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", rpc_port, "register",
                                    {{"domain", domain}});
        std::cout << result.dump(2) << "\n";
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

static int cmd_send(int argc, char** argv) {
    if (argc < 2) { std::cerr << "Usage: determ send <to_domain> <amount> [--fee <n>]\n"; return 1; }
    std::string to     = argv[0];
    uint64_t    amount = 0;
    if (!arg_u64("send", "<amount>", argv[1], amount)) return 1;
    uint64_t    fee    = 0;
    uint16_t    port   = get_rpc_port(argc, argv);
    for (int i = 2; i < argc - 1; ++i)
        if (std::string(argv[i]) == "--fee") { if (!arg_u64("send", "--fee", argv[i + 1], fee)) return 1; }
    return submit_tx_with_retry(port, "send",
        {{"to", to}, {"amount", amount}, {"fee", fee}});
}

// determ status [--field <name>] [--rpc-port N]
//   Print the status RPC JSON (default behavior, full dump). With
//   --field <name>, prints just the value of that top-level field
//   (one-shot extraction for shell scripts). Empty string is printed
//   for absent/null fields; non-scalar values are dumped compactly.
//   Examples:
//     determ status                             # full JSON
//     determ status --field height              # just an integer
//     determ status --field committee_region    # just a string
//     determ status --field protections         # compact object dump
static int cmd_status(int argc, char** argv) {
    std::string field;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--field" && i + 1 < argc) field = argv[i + 1];
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "status");
        if (!field.empty()) {
            // Field-extraction mode: print one value (no JSON envelope).
            if (!result.contains(field) || result[field].is_null()) {
                // Empty line for absent / null — operators can check exit 0.
                std::cout << "\n";
                return 0;
            }
            auto& v = result[field];
            if (v.is_string())       std::cout << v.get<std::string>() << "\n";
            else if (v.is_number())  std::cout << v.dump()              << "\n";
            else if (v.is_boolean()) std::cout << (v.get<bool>() ? "true" : "false") << "\n";
            else                     std::cout << v.dump()              << "\n";
            return 0;
        }
        std::cout << result.dump(2) << "\n";
    } catch (std::exception& e) {
        std::cerr << "Error (is the node running?): " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ summary [--json] [--rpc-port P]
//   Operator dashboard. Gathers the most-frequently-checked status
//   fields into a single compact view: height + head_hash, peer +
//   committee + mempool sizes, this node's committee_region, sync
//   state, A1 invariant status. Designed for the common SSH-into-
//   server quick-check workflow — one line summarizes "is the node
//   healthy + caught up + connected?".
//
//   Uses `status` RPC for most fields + `chain_summary` (last_n=1)
//   for A1 counter aggregation. No new server RPC required.
//
//   Default output (human-readable):
//     height       : N
//     head_hash    : <prefix>...
//     genesis      : <prefix>...
//     peers        : N
//     mempool      : N
//     committee    : N (region: <r>)
//     sync_state   : in_sync | syncing
//     A1 invariant : OK | VIOLATED
//
//   --json emits a structured envelope for monitoring dashboards.
static int cmd_summary(int argc, char** argv) {
    bool json_out = false;
    for (int i = 0; i < argc; ++i) {
        if (std::string(argv[i]) == "--json") { json_out = true; break; }
    }
    uint16_t port = get_rpc_port(argc, argv);

    try {
        auto st = rpc::rpc_call("127.0.0.1", port, "status");
        if (!st.is_object()) {
            std::cerr << "Error: status RPC returned non-object\n";
            return 1;
        }

        // Pull A1 counters from chain_summary (last_n=1 for min payload).
        json cs_params = {{"last_n", uint32_t{1}}};
        auto cs = rpc::rpc_call("127.0.0.1", port, "chain_summary", cs_params);
        if (!cs.is_object()) {
            std::cerr << "Error: chain_summary RPC returned non-object\n";
            return 1;
        }
        uint64_t genesis_total   = cs.value("genesis_total",       uint64_t{0});
        uint64_t accum_subsidy   = cs.value("accumulated_subsidy", uint64_t{0});
        uint64_t accum_inbound   = cs.value("accumulated_inbound", uint64_t{0});
        uint64_t accum_slashed   = cs.value("accumulated_slashed", uint64_t{0});
        uint64_t accum_outbound  = cs.value("accumulated_outbound",uint64_t{0});
        uint64_t live_supply     = cs.value("total_supply",        uint64_t{0});
        uint64_t expected =
            genesis_total + accum_subsidy + accum_inbound
            - accum_slashed - accum_outbound;
        bool a1_ok = (expected == live_supply);

        // Pull peer count + mempool from status; pull committee from
        // dedicated RPC (always-current value).
        uint64_t height       = st.value("height", uint64_t{0});
        std::string head_hash = st.value("head_hash", std::string{});
        std::string genesis_h = st.value("genesis",   std::string{});
        uint64_t peer_count   = st.value("peer_count", uint64_t{0});
        uint64_t mempool_size = st.value("mempool_size", uint64_t{0});
        std::string sync      = st.value("sync_state", std::string{"unknown"});
        std::string region    = st.value("committee_region", std::string{});

        // Committee size — fetch dedicated array.
        size_t committee_size = 0;
        try {
            auto cmt = rpc::rpc_call("127.0.0.1", port, "committee");
            if (cmt.is_array()) committee_size = cmt.size();
        } catch (...) { /* leave 0 on failure — partial summary is OK */ }

        if (json_out) {
            json env = {
                {"height",         height},
                {"head_hash",      head_hash},
                {"genesis",        genesis_h},
                {"peers",          peer_count},
                {"mempool",        mempool_size},
                {"committee",      committee_size},
                {"committee_region", region},
                {"sync_state",     sync},
                {"a1_invariant_ok", a1_ok},
                {"live_total_supply", live_supply},
                {"expected_total",    expected}
            };
            std::cout << env.dump() << "\n";
            return a1_ok ? 0 : 2;
        }

        auto truncate = [](const std::string& s) {
            return s.size() > 24 ? s.substr(0, 24) + "..." : s;
        };
        std::cout << "height       : " << height       << "\n"
                  << "head_hash    : " << truncate(head_hash) << "\n"
                  << "genesis      : " << truncate(genesis_h) << "\n"
                  << "peers        : " << peer_count   << "\n"
                  << "mempool      : " << mempool_size << "\n"
                  << "committee    : " << committee_size
                  << " (region: "      << (region.empty() ? "(global)" : region)
                  << ")\n"
                  << "sync_state   : " << sync         << "\n"
                  << "A1 invariant : " << (a1_ok ? "OK" : "VIOLATED") << "\n";
        return a1_ok ? 0 : 2;
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
}

// determ show-block <index> [--rpc-port N]
//   Prints the full block at the given index from a running node.
static int cmd_show_block(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ show-block <index> [--rpc-port N]\n";
        return 1;
    }
    uint64_t index = 0;
    if (!arg_u64("show-block", "<index>", argv[0], index)) return 1;
    uint16_t port = get_rpc_port(argc, argv);
    try {
        json params = {{"index", index}};
        auto result = rpc::rpc_call("127.0.0.1", port, "block", params);
        if (result.is_null()) {
            std::cerr << "Block " << index << " out of range (chain.height too low)\n";
            return 1;
        }
        std::cout << result.dump(2) << "\n";
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// v2.2 light-client committee-signature verifier.
//
// Usage: determ verify-block-sigs --header <file> --committee <file>
//                                  [--bft]
//
// Reads a single block header (from `determ headers` or `show-block`)
// and a committee pubkey map, then verifies that each `creators[i]`'s
// `creator_block_sigs[i]` is a valid Ed25519 signature over
// `compute_block_digest(b)` under the pubkey associated with that
// creator's domain.
//
// The committee file is a JSON object with a `members` array — same
// shape the `committee` RPC returns:
//
//   {
//     "members": [
//       {"domain": "node1", "ed_pub": "<64-char hex>"},
//       {"domain": "node2", "ed_pub": "<64-char hex>"},
//       ...
//     ]
//   }
//
// (Or accept the raw committee RPC response directly — the response is
// the array itself.)
//
// Optional `--bft`: in BFT mode the required threshold is
// Q = ceil(2 * |creators| / 3) instead of full K-of-K. Without this
// determ verify-genesis --in genesis.json [--json] [--expected-hash HEX]
//   Standalone genesis.json validator. Loads the file, applies the
//   same parsing + sane-bounds checks as `determ start`, computes the
//   chain-identity hash via compute_genesis_hash, prints a structured
//   summary (human-readable by default, single-line JSON with --json).
//   Optional --expected-hash compares the computed identity against an
//   externally-trusted pin; exits non-zero with a clear diagnostic
//   when they differ.
//
// Useful workflows:
//   * Pre-deployment: verify the genesis.json hashes to the value the
//     operator expects (defeats config-rewrite-attacks where a
//     deployment template smuggles in a different chain identity).
//   * Cross-team coordination: each team independently computes the
//     hash from their checked-in genesis.json and compares.
//   * Cluster onboarding: a new operator's genesis must match the
//     existing cluster's pinned hash.
//
// Note re: S-039 (Low/Op diagnostic-UX gap, see docs/SECURITY.md §S-039):
// `compute_genesis_hash` does NOT bind operational params like
// m_creators, k_block_sigs, block_subsidy, min_stake, initial_shard_count,
// bft_enabled. Two genesis.json files differing ONLY in those fields
// produce the same identity hash. This command prints those fields
// explicitly in the output so operators can spot mismatches via direct
// inspection even though the hash itself doesn't catch them.
static int cmd_verify_genesis(int argc, char** argv) {
    std::string in_path;
    std::string expected_hash_hex;
    bool json_out = false;
    for (int i = 0; i < argc - 1; ++i) {
        if (std::string(argv[i]) == "--in") in_path = argv[i + 1];
        else if (std::string(argv[i]) == "--expected-hash") expected_hash_hex = argv[i + 1];
    }
    for (int i = 0; i < argc; ++i) {
        if (std::string(argv[i]) == "--json") json_out = true;
    }
    if (in_path.empty()) {
        std::cerr << "Usage: determ verify-genesis --in <genesis.json> "
                     "[--expected-hash <hex64>] [--json]\n";
        return 1;
    }

    auto emit_error = [&](const std::string& code, const std::string& msg) {
        if (json_out) {
            json err = {{"status", "error"}, {"code", code}, {"message", msg}};
            std::cout << err.dump() << "\n";
        } else {
            std::cerr << "FAIL: " << msg << "\n";
        }
    };

    try {
        std::ifstream f(in_path);
        if (!f) {
            emit_error("cannot_open", "cannot open " + in_path);
            return 1;
        }
        json j = json::parse(f);
        chain::GenesisConfig cfg = chain::GenesisConfig::from_json(j);

        // compute_genesis_hash (the identity contract). The from_json
        // path above already applied sane-bounds checks for subsidy
        // overflow + genesis_message size + LOTTERY multiplier
        // constraints — those throw at parse time.
        Hash hash = chain::compute_genesis_hash(cfg);

        // Build the result + optionally compare against external pin.
        json result = {
            {"status",                "ok"},
            {"path",                  in_path},
            {"genesis_hash",          to_hex(hash)},
            {"chain_id",              cfg.chain_id},
            {"chain_role",            static_cast<uint8_t>(cfg.chain_role)},
            {"shard_id",              cfg.shard_id},
            {"initial_creators",      cfg.initial_creators.size()},
            {"initial_balances",      cfg.initial_balances.size()},
            // Operational params — S-039 CLOSED: these are now bound into
            // compute_genesis_hash, so a config mismatch changes the
            // genesis_hash and is caught at the HELLO handshake. Emitted
            // here for operator visibility.
            {"m_creators",            cfg.m_creators},
            {"k_block_sigs",          cfg.k_block_sigs},
            {"block_subsidy",         cfg.block_subsidy},
            {"min_stake",             cfg.min_stake},
            {"initial_shard_count",   cfg.initial_shard_count},
            {"bft_enabled",           cfg.bft_enabled},
            // Identity / message fields (also bound into the hash):
            {"genesis_message_is_default",
                cfg.genesis_message == chain::DEFAULT_GENESIS_MESSAGE},
            {"genesis_message_bytes", cfg.genesis_message.size()},
            {"committee_region",      cfg.committee_region},
        };

        // Optional external-pin comparison.
        bool pin_match = true;
        if (!expected_hash_hex.empty()) {
            if (expected_hash_hex.size() != 64) {
                emit_error("invalid_expected_hash_length",
                    "expected-hash must be 64 hex chars, got "
                    + std::to_string(expected_hash_hex.size()));
                return 1;
            }
            Hash expected = from_hex_arr<32>(expected_hash_hex);
            pin_match = (expected == hash);
            result["expected_hash_match"] = pin_match;
        }

        if (json_out) {
            std::cout << result.dump() << "\n";
        } else {
            std::cout << "genesis OK: " << in_path << "\n";
            std::cout << "  genesis_hash       : " << to_hex(hash) << "\n";
            std::cout << "  chain_id           : " << cfg.chain_id << "\n";
            std::cout << "  chain_role         : "
                      << static_cast<int>(cfg.chain_role) << "\n";
            std::cout << "  shard_id           : " << cfg.shard_id << "\n";
            std::cout << "  initial_creators   : " << cfg.initial_creators.size() << "\n";
            std::cout << "  initial_balances   : " << cfg.initial_balances.size() << "\n";
            std::cout << "  --- operational params (S-039 CLOSED: bound to genesis hash) ---\n";
            std::cout << "  m_creators         : " << cfg.m_creators << "\n";
            std::cout << "  k_block_sigs       : " << cfg.k_block_sigs << "\n";
            std::cout << "  block_subsidy      : " << cfg.block_subsidy << "\n";
            std::cout << "  min_stake          : " << cfg.min_stake << "\n";
            std::cout << "  initial_shard_count: " << cfg.initial_shard_count << "\n";
            std::cout << "  bft_enabled        : "
                      << (cfg.bft_enabled ? "true" : "false") << "\n";
            std::cout << "  --- identity-bound fields ---\n";
            std::cout << "  genesis_message    : "
                      << (cfg.genesis_message == chain::DEFAULT_GENESIS_MESSAGE
                              ? "(default)"
                              : "(custom, " + std::to_string(cfg.genesis_message.size()) + " bytes)")
                      << "\n";
            std::cout << "  committee_region   : "
                      << (cfg.committee_region.empty() ? "(none)" : cfg.committee_region)
                      << "\n";
            if (!expected_hash_hex.empty()) {
                if (pin_match) {
                    std::cout << "  expected hash      : ✓ matches\n";
                } else {
                    std::cerr << "FAIL: genesis_hash does NOT match --expected-hash\n";
                    std::cerr << "  computed: " << to_hex(hash) << "\n";
                    std::cerr << "  expected: " << expected_hash_hex << "\n";
                }
            }
        }
        return pin_match ? 0 : 1;
    } catch (std::exception& e) {
        emit_error("parse_or_validation_error", e.what());
        return 1;
    }
}

// flag, every creators[i] must have a non-zero verifying signature
// (MD-mode K-of-K).
//
// Returns 0 on success with a structured summary; non-zero with a FAIL
// diagnostic on signature mismatch or missing committee member.
//
// Pure committee-signature check. Does NOT verify the prev_hash chain
// (use `verify-headers` for that) or the state_root (compute_state_root
// can't be re-derived without the full state — use the verified header
// to anchor verify-state-proof / snapshot inspect --state-root).
static int cmd_verify_block_sigs(int argc, char** argv) {
    std::string header_path;
    std::string committee_path;
    bool bft_mode = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if      (a == "--header"    && i + 1 < argc) header_path    = argv[i + 1];
        else if (a == "--committee" && i + 1 < argc) committee_path = argv[i + 1];
        else if (a == "--bft") bft_mode = true;
    }
    if (header_path.empty() || committee_path.empty()) {
        std::cerr << "Usage: determ verify-block-sigs --header <file> "
                     "--committee <file> [--bft]\n";
        return 1;
    }

    // Read header + committee.
    nlohmann::json hjson, cjson;
    try {
        std::ifstream hf(header_path);
        if (!hf) throw std::runtime_error("cannot open header: " + header_path);
        hjson = nlohmann::json::parse(hf);
        std::ifstream cf(committee_path);
        if (!cf) throw std::runtime_error("cannot open committee: " + committee_path);
        cjson = nlohmann::json::parse(cf);
    } catch (std::exception& e) {
        std::cerr << "verify-block-sigs: parse error: " << e.what() << "\n";
        return 1;
    }

    // If the header file is actually a `determ headers` response
    // (`{headers: [...], ...}`), pull out the first header.
    if (hjson.contains("headers") && hjson["headers"].is_array()) {
        if (hjson["headers"].empty()) {
            std::cerr << "verify-block-sigs: header file has empty "
                         "headers array — nothing to verify\n";
            return 1;
        }
        hjson = hjson["headers"][0];
    }

    // Pad stripped header back to a Block-parseable shape: the heavy
    // collections that the `headers` RPC erases (transactions,
    // cross_shard_receipts, inbound_receipts, initial_state) are
    // NOT in compute_block_digest's input, so empty arrays are
    // semantically equivalent for our purposes.
    if (!hjson.contains("transactions"))         hjson["transactions"]         = nlohmann::json::array();
    if (!hjson.contains("cross_shard_receipts")) hjson["cross_shard_receipts"] = nlohmann::json::array();
    if (!hjson.contains("inbound_receipts"))     hjson["inbound_receipts"]     = nlohmann::json::array();
    if (!hjson.contains("initial_state"))        hjson["initial_state"]        = nlohmann::json::array();

    chain::Block b;
    try {
        b = chain::Block::from_json(hjson);
    } catch (std::exception& e) {
        std::cerr << "verify-block-sigs: malformed header: "
                  << e.what() << "\n";
        return 1;
    }

    // Build domain → pubkey lookup from the committee JSON. Accept
    // both `{members: [...]}` (shape with envelope) and raw array.
    nlohmann::json members;
    if (cjson.is_array()) members = cjson;
    else if (cjson.contains("members") && cjson["members"].is_array())
        members = cjson["members"];
    else {
        std::cerr << "verify-block-sigs: committee file must be a JSON "
                     "array or an object with a 'members' array\n";
        return 1;
    }

    std::map<std::string, PubKey> pubkey_of;
    try {
        for (auto& m : members) {
            std::string domain = m.value("domain", std::string{});
            std::string ed_hex = m.value("ed_pub", std::string{});
            if (domain.empty() || ed_hex.empty()) continue;
            if (ed_hex.size() != 64) {
                throw std::runtime_error(
                    "committee member '" + domain
                    + "' has malformed ed_pub (expected 64 hex chars, got "
                    + std::to_string(ed_hex.size()) + ")");
            }
            pubkey_of[domain] = from_hex_arr<32>(ed_hex);
        }
    } catch (std::exception& e) {
        std::cerr << "verify-block-sigs: " << e.what() << "\n";
        return 1;
    }
    if (pubkey_of.empty()) {
        std::cerr << "verify-block-sigs: committee file has no valid "
                     "members\n";
        return 1;
    }

    // Sanity: every creator in the block must be in the committee.
    for (auto& d : b.creators) {
        if (pubkey_of.find(d) == pubkey_of.end()) {
            std::cerr << "FAIL: creator '" << d << "' is not in the "
                         "supplied committee — cannot verify their "
                         "signature\n";
            return 1;
        }
    }
    if (b.creator_block_sigs.size() != b.creators.size()) {
        std::cerr << "FAIL: creator_block_sigs.size (" << b.creator_block_sigs.size()
                  << ") != creators.size (" << b.creators.size() << ")\n";
        return 1;
    }

    // Compute the digest that the committee signed.
    Hash digest = node::compute_block_digest(b);

    // Verify each creator's signature. In MD mode, every creator must
    // have a valid sig (sentinel-zero NOT allowed). In BFT mode, count
    // non-zero verifying sigs and check against Q = ceil(2K/3).
    Signature zero_sig{};
    size_t valid = 0;
    std::vector<std::string> failures;
    for (size_t i = 0; i < b.creators.size(); ++i) {
        const auto& sig = b.creator_block_sigs[i];
        if (sig == zero_sig) {
            if (!bft_mode) {
                failures.push_back("creator[" + std::to_string(i) + "] '"
                                    + b.creators[i] + "': sentinel-zero "
                                    "signature not allowed in MD mode");
            }
            // BFT: zero is a valid sentinel slot; just don't count.
            continue;
        }
        const auto& pk = pubkey_of.at(b.creators[i]);
        bool ok = crypto::verify(pk, digest.data(), digest.size(), sig);
        if (ok) {
            valid++;
        } else {
            failures.push_back("creator[" + std::to_string(i) + "] '"
                                + b.creators[i] + "': signature does NOT "
                                "verify against compute_block_digest");
        }
    }

    size_t required = bft_mode
        ? (2 * b.creators.size() + 2) / 3   // ceil(2K/3)
        : b.creators.size();                 // full K-of-K

    if (valid >= required && failures.empty()) {
        std::cout << "OK\n";
        std::cout << "  block_index:    " << b.index << "\n";
        std::cout << "  mode:           "
                  << (bft_mode ? "BFT (threshold "
                                + std::to_string(required) + "/"
                                + std::to_string(b.creators.size())
                                + ")"
                              : "MD (full K-of-K)") << "\n";
        std::cout << "  verified sigs:  " << valid << "/"
                  << b.creators.size() << "\n";
        std::cout << "  digest:         " << to_hex(digest) << "\n";
        if (!b.state_root.empty() || b.state_root != Hash{}) {
            std::cout << "  state_root:     " << to_hex(b.state_root)
                      << "\n";
        }
        return 0;
    } else {
        std::cerr << "FAIL: committee-signature verification\n";
        std::cerr << "  block_index:   " << b.index << "\n";
        std::cerr << "  mode:          "
                  << (bft_mode ? "BFT" : "MD") << "\n";
        std::cerr << "  verified sigs: " << valid << "/"
                  << b.creators.size()
                  << " (required " << required << ")\n";
        for (auto& f : failures) std::cerr << "  " << f << "\n";
        return 1;
    }
}

// v2.2 light-client header-chain verifier.
//
// Usage: determ verify-headers [--in file] [--genesis-hash <hex64>]
//                              [--prev-hash <hex64>]
//
// Reads a `determ headers` response (JSON) from --in or stdin and
// verifies that the prev_hash chain links correctly between
// consecutive headers: header[i].prev_hash == header[i-1].block_hash.
//
// Optional --genesis-hash <hex64>: if the headers slice starts at
// index 0, the first header's prev_hash should equal Hash{} (32 zero
// bytes — the canonical "no parent" marker). If --genesis-hash is
// supplied, it's also checked against the genesis header's block_hash.
// Useful when bootstrapping from a known genesis pin.
//
// Optional --prev-hash <hex64>: if the headers slice starts at some
// index > 0, the first header's prev_hash must equal this supplied
// hash (= block_hash of the block immediately preceding the slice).
// Light clients use this to extend a previously-verified header
// range with a new fetched slice.
//
// Does NOT verify committee signatures on each header (that requires
// a NodeRegistry + epoch-rand derivation; out of scope for this
// stdalone CLI). This is the chain-of-hashes integrity check —
// catches a server returning misaligned / re-ordered headers.
static int cmd_verify_headers(int argc, char** argv) {
    std::string in_path;
    std::string genesis_hash_hex;
    std::string prev_hash_hex;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if      (a == "--in"            && i + 1 < argc) in_path          = argv[i + 1];
        else if (a == "--genesis-hash"  && i + 1 < argc) genesis_hash_hex = argv[i + 1];
        else if (a == "--prev-hash"     && i + 1 < argc) prev_hash_hex    = argv[i + 1];
    }

    nlohmann::json doc;
    try {
        if (!in_path.empty()) {
            std::ifstream f(in_path);
            if (!f) throw std::runtime_error("cannot open: " + in_path);
            doc = nlohmann::json::parse(f);
        } else {
            doc = nlohmann::json::parse(std::cin);
        }
    } catch (std::exception& e) {
        std::cerr << "verify-headers: parse error: " << e.what() << "\n";
        return 1;
    }

    if (!doc.contains("headers") || !doc["headers"].is_array()) {
        std::cerr << "verify-headers: input missing 'headers' array "
                     "(expected `determ headers` response)\n";
        return 1;
    }
    auto& headers = doc["headers"];
    if (headers.empty()) {
        std::cout << "OK (empty headers slice, nothing to verify)\n";
        return 0;
    }

    // Helper: pull required hex field from one header.
    auto h_get = [](const nlohmann::json& h, const char* field,
                       size_t expected_chars) -> std::string {
        if (!h.contains(field) || !h[field].is_string())
            throw std::runtime_error(
                std::string("header missing '") + field + "' field");
        std::string s = h[field].get<std::string>();
        if (s.size() != expected_chars)
            throw std::runtime_error(
                std::string("header '") + field
                + "' has wrong length: expected "
                + std::to_string(expected_chars) + " chars, got "
                + std::to_string(s.size()));
        return s;
    };

    try {
        // Check the first header's prev_hash against the appropriate
        // anchor: --genesis-hash (if index 0), --prev-hash (if not 0),
        // or just print a note (if no anchor supplied).
        uint64_t first_index = headers[0].value("index", uint64_t{0});
        std::string first_prev = h_get(headers[0], "prev_hash", 64);

        if (first_index == 0) {
            // Genesis: prev_hash must be 32-zero-bytes (the canonical
            // "no parent" marker).
            std::string zero64(64, '0');
            if (first_prev != zero64) {
                std::cerr << "FAIL: genesis header (index 0) has "
                             "non-zero prev_hash: " << first_prev << "\n";
                return 1;
            }
            // Optional: verify the supplied --genesis-hash matches the
            // genesis header's block_hash.
            if (!genesis_hash_hex.empty()) {
                std::string gh = h_get(headers[0], "block_hash", 64);
                if (gh != genesis_hash_hex) {
                    std::cerr << "FAIL: genesis block_hash mismatch\n"
                              << "  header reports: " << gh << "\n"
                              << "  --genesis-hash: " << genesis_hash_hex << "\n";
                    return 1;
                }
            }
        } else if (!prev_hash_hex.empty()) {
            // Non-genesis start: first header's prev_hash must match
            // the supplied --prev-hash anchor.
            if (first_prev != prev_hash_hex) {
                std::cerr << "FAIL: first header's prev_hash doesn't "
                             "match supplied --prev-hash\n"
                          << "  header prev_hash: " << first_prev << "\n"
                          << "  --prev-hash:     " << prev_hash_hex << "\n";
                return 1;
            }
        }
        // (If neither --genesis-hash nor --prev-hash is supplied and
        // we don't start at 0, the first prev_hash is unanchored —
        // we just verify the internal chain links and report it.)

        // Walk consecutive header pairs and verify prev_hash chain.
        for (size_t i = 1; i < headers.size(); ++i) {
            std::string prev = h_get(headers[i], "prev_hash", 64);
            std::string prior_hash = h_get(headers[i - 1], "block_hash", 64);
            if (prev != prior_hash) {
                std::cerr << "FAIL: prev_hash chain break at header "
                          << i << " (index "
                          << headers[i].value("index", uint64_t{0}) << ")\n"
                          << "  prev_hash:        " << prev << "\n"
                          << "  prior block_hash: " << prior_hash << "\n";
                return 1;
            }
        }
    } catch (std::exception& e) {
        std::cerr << "verify-headers: " << e.what() << "\n";
        return 1;
    }

    std::cout << "OK\n";
    std::cout << "  verified " << headers.size()
              << " header(s) " << headers[0].value("index", uint64_t{0})
              << ".." << headers.back().value("index", uint64_t{0}) << "\n";
    if (!genesis_hash_hex.empty()) {
        std::cout << "  genesis pin: ✓ matches supplied --genesis-hash\n";
    } else if (!prev_hash_hex.empty()) {
        std::cout << "  prev pin:    ✓ matches supplied --prev-hash\n";
    }
    return 0;
}

// v2.2 light-client header-sync CLI.
//
// Two fetch paths:
//
//   1. RPC fetch (default):
//        determ headers [--from N] [--count M] [--rpc-port P]
//      Connects to a local node's RPC port. Returns the same
//      {headers, from, count, height} envelope `rpc_headers`
//      produces.
//
//   2. Gossip-layer fetch (light-client mode):
//        determ headers --peer host:port [--from N] [--count M]
//      Connects directly to a remote node's gossip port, exchanges
//      HELLO + HEADERS_REQUEST, waits for HEADERS_RESPONSE. No RPC
//      binding required — peers don't have to expose RPC for light
//      clients to consume headers. This is the missing v2.2
//      gossip-layer piece (HEADERS_REQUEST / HEADERS_RESPONSE wire
//      messages); same envelope shape, same content as the RPC
//      path so all downstream verifier CLIs (verify-headers,
//      verify-block-sigs) work identically.
//
// Returns a slice of block headers — the same Block JSON shape that
// `show-block` emits, but with the heavy `transactions`,
// `cross_shard_receipts`, `inbound_receipts`, and `initial_state`
// fields stripped. Light clients use this to verify committee
// signatures + extract state_root for verify-state-proof anchoring,
// without the bandwidth cost of fetching every tx.
//
// Defaults: --from 0, --count 16. Server caps count at 256.
static int cmd_headers(int argc, char** argv) {
    uint64_t from_index = 0;
    uint32_t count = 16;
    std::string peer_str;
    for (int i = 0; i < argc - 1; ++i) {
        std::string a = argv[i];
        if      (a == "--from")  { if (!arg_u64("headers", "--from", argv[i + 1], from_index)) return 1; }
        else if (a == "--count") { if (!arg_u32("headers", "--count", argv[i + 1], count)) return 1; }
        else if (a == "--peer")  peer_str = argv[i + 1];
    }

    // Path 2: gossip-layer fetch via --peer host:port.
    if (!peer_str.empty()) {
        auto colon = peer_str.find(':');
        if (colon == std::string::npos) {
            std::cerr << "--peer must be host:port\n";
            return 1;
        }
        std::string host = peer_str.substr(0, colon);
        uint16_t port = static_cast<uint16_t>(
            std::stoi(peer_str.substr(colon + 1)));
        try {
            net::SyncClient client;
            client.connect(host, port);

            auto write_msg = [&](const net::Message& msg) {
                auto buf = msg.serialize();
                client.write_all(buf.data(), buf.size());
            };

            // HELLO + HEADERS_REQUEST. Tag ourselves SINGLE/0 since
            // light clients don't claim a chain identity (matches
            // the snapshot-fetcher pattern).
            write_msg(net::make_hello("headers-fetcher", 0,
                                        ChainRole::SINGLE, 0));
            write_msg(net::make_headers_request(from_index, count));

            // Read framed messages until HEADERS_RESPONSE arrives.
            // Skip any others (peer might be gossiping blocks /
            // headers / etc. concurrently).
            std::array<uint8_t, 4> hdr;
            for (int spin = 0; spin < 200; ++spin) {
                client.read_exact(hdr.data(), hdr.size());
                uint32_t len = (uint32_t(hdr[0]) << 24)
                             | (uint32_t(hdr[1]) << 16)
                             | (uint32_t(hdr[2]) <<  8)
                             |  uint32_t(hdr[3]);
                if (len == 0 || len > 16 * 1024 * 1024) {
                    std::cerr << "headers fetch: bad frame length "
                              << len << "\n";
                    return 1;
                }
                std::vector<uint8_t> body(len);
                client.read_exact(body.data(), body.size());
                net::Message m = net::Message::deserialize(body.data(),
                                                              body.size());
                if (m.type != net::MsgType::HEADERS_RESPONSE) continue;
                std::cout << m.payload.dump(2) << "\n";
                return 0;
            }
            std::cerr << "headers fetch: timed out waiting for "
                         "HEADERS_RESPONSE\n";
            return 1;
        } catch (std::exception& e) {
            std::cerr << "headers fetch error: " << e.what() << "\n";
            return 1;
        }
    }

    // Path 1: RPC fetch (default).
    uint16_t port = get_rpc_port(argc, argv);
    try {
        json params = {{"from", from_index}, {"count", count}};
        auto result = rpc::rpc_call("127.0.0.1", port, "headers", params);
        std::cout << result.dump(2) << "\n";
        return 0;
    } catch (std::exception& e) {
        std::cerr << "headers query failed: " << e.what() << "\n";
        return 1;
    }
}

// determ validators [--json] [--rpc-port N]
//   Lists the current validator pool (registered + active + staked +
//   not suspended). Default output is a human-readable table; --json
//   emits the raw RPC array verbatim, suitable for feeding directly
//   into `verify-block-sigs --committee` or any other machine
//   consumer.
// determ validators [--filter-region R] [--json] [--rpc-port N]
//   List the registered validator pool. Default columns:
//     domain | stake | active_from | region | ed_pub (truncated)
//
//   --filter-region R post-filters to validators with region == R
//   (case-sensitive exact match; empty filter = no filter). Useful in
//   regional deployments to inspect just the locally-eligible pool
//   (rev.9 R1 + region-pinned committee selection).
//
//   --json passes the (filtered) RPC array through verbatim — same
//   shape `verify-block-sigs --committee` consumes.
static int cmd_validators(int argc, char** argv) {
    bool json_out = false;
    bool count_only = false;
    std::string filter_region;
    bool have_filter = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json")        json_out   = true;
        else if (a == "--count")  count_only = true;
        else if (a == "--filter-region" && i + 1 < argc) {
            have_filter = true;
            filter_region = argv[i + 1];
        }
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "validators");

        // Post-filter on region. The RPC always returns the full pool
        // (sorted); we drop entries whose region doesn't match.
        if (have_filter) {
            json filtered = json::array();
            for (auto& v : result) {
                if (v.value("region", std::string{}) == filter_region) {
                    filtered.push_back(v);
                }
            }
            result = std::move(filtered);
        }

        // --count: bare integer (count of validators after region filter)
        // for shell scripts. Composes with --filter-region (count just
        // the regional subset) and --json (emit `{"count": N}`). Defends
        // against non-array responses by reporting 0.
        if (count_only) {
            size_t n = result.is_array() ? result.size() : 0;
            if (json_out) std::cout << json({{"count", n}}).dump() << "\n";
            else          std::cout << n << "\n";
            return 0;
        }

        if (json_out) {
            std::cout << result.dump(2) << "\n";
            return 0;
        }
        if (!result.is_array() || result.empty()) {
            if (have_filter) {
                std::cout << "(no eligible validators in region '"
                          << filter_region << "')\n";
            } else {
                std::cout << "(no eligible validators)\n";
            }
            return 0;
        }
        std::cout << std::left
                  << std::setw(25) << "domain"
                  << std::setw(10) << "stake"
                  << std::setw(15) << "active_from"
                  << std::setw(12) << "region"
                  << "ed_pub\n";
        for (auto& v : result) {
            std::string region = v.value("region", std::string{});
            if (region.empty()) region = "(global)";
            std::cout << std::setw(25) << v.value("domain", std::string{})
                      << std::setw(10) << v.value("stake", uint64_t{0})
                      << std::setw(15) << v.value("active_from", uint64_t{0})
                      << std::setw(12) << region.substr(0, 11)
                      << v.value("ed_pub", std::string{}).substr(0, 24) << "...\n";
        }
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ stakes [--top N] [--json] [--rpc-port P]
//   List validators sorted by stake DESCENDING. Complements
//   `determ validators` (which sorts alphabetically by domain).
//   Operator use cases:
//     - "Who are the top stakers?" — for slashing impact analysis,
//        committee-influence assessment, governance signal.
//     - "Why does region X have low committee participation?" —
//        sorted-by-stake view immediately shows whether the region's
//        validators are min-staked or fully staked.
//
//   --top N        : truncate to top N entries (default = unlimited)
//   --json         : emit the (filtered + sorted) entries as a JSON
//                    array; entries match `validators` RPC shape
//                    (domain, stake, active_from, region, ed_pub)
//                    with the addition of explicit `rank` index.
//
//   Pulls from the `validators` RPC and sorts client-side. No new
//   server method needed. Zero-stake entries kept (they may be
//   pre-genesis registrants in DOMAIN_INCLUSION mode); tie-breaks
//   by domain ascending.
static int cmd_stakes(int argc, char** argv) {
    uint32_t top_n = 0;  // 0 = unlimited
    bool have_top = false;
    bool json_out = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--top" && i + 1 < argc) {
            try { top_n = uint32_t(std::stoul(argv[i + 1])); have_top = true; }
            catch (...) { std::cerr << "Error: --top must be unsigned\n"; return 1; }
        }
        else if (a == "--json") json_out = true;
    }
    uint16_t port = get_rpc_port(argc, argv);

    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "validators");
        if (!result.is_array()) {
            std::cerr << "Error: validators RPC returned non-array\n";
            return 1;
        }

        // Materialize entries with stake as sort key.
        struct Entry {
            std::string domain;
            uint64_t    stake;
            uint64_t    active_from;
            std::string region;
            std::string ed_pub;
        };
        std::vector<Entry> entries;
        entries.reserve(result.size());
        for (auto& v : result) {
            Entry e;
            e.domain      = v.value("domain", std::string{});
            e.stake       = v.value("stake", uint64_t{0});
            e.active_from = v.value("active_from", uint64_t{0});
            e.region      = v.value("region", std::string{});
            e.ed_pub      = v.value("ed_pub", std::string{});
            entries.push_back(std::move(e));
        }

        // Sort by stake DESC, ties broken by domain ASC.
        std::sort(entries.begin(), entries.end(),
                  [](const Entry& a, const Entry& b) {
                      if (a.stake != b.stake) return a.stake > b.stake;
                      return a.domain < b.domain;
                  });

        // Truncate to top N.
        size_t limit = have_top ? std::min<size_t>(top_n, entries.size())
                                : entries.size();

        if (json_out) {
            json arr = json::array();
            for (size_t i = 0; i < limit; ++i) {
                const auto& e = entries[i];
                arr.push_back({
                    {"rank",        i + 1},  // 1-indexed for human readability
                    {"domain",      e.domain},
                    {"stake",       e.stake},
                    {"active_from", e.active_from},
                    {"region",      e.region},
                    {"ed_pub",      e.ed_pub}
                });
            }
            std::cout << arr.dump(2) << "\n";
            return 0;
        }

        if (limit == 0) {
            std::cout << "(no validators)\n";
            return 0;
        }
        std::cout << std::left
                  << std::setw(6)  << "rank"
                  << std::setw(25) << "domain"
                  << std::setw(12) << "stake"
                  << std::setw(15) << "active_from"
                  << std::setw(12) << "region"
                  << "ed_pub\n";
        for (size_t i = 0; i < limit; ++i) {
            const auto& e = entries[i];
            std::cout << std::setw(6)  << (i + 1)
                      << std::setw(25) << e.domain
                      << std::setw(12) << e.stake
                      << std::setw(15) << e.active_from
                      << std::setw(12) << (e.region.empty() ? "(global)" : e.region)
                      << e.ed_pub.substr(0, 24) << "...\n";
        }
        return 0;
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
}

// determ chain-summary [--last N] [--json] [--rpc-port N]
//   Prints a compact summary of the last N blocks (default 10).
//   Default output is human-readable; --json emits the raw RPC
//   response verbatim (the {blocks, height, total_supply, ...}
//   object including A1 supply counters).
static int cmd_chain_summary(int argc, char** argv) {
    uint32_t last_n = 10;
    bool json_out = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if      (a == "--last" && i + 1 < argc) { if (!arg_u32("chain-summary", "--last", argv[i + 1], last_n)) return 1; }
        else if (a == "--json") json_out = true;
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        json params = {{"last_n", last_n}};
        auto result = rpc::rpc_call("127.0.0.1", port, "chain_summary", params);
        if (json_out) {
            std::cout << result.dump(2) << "\n";
            return 0;
        }
        // A1: chain_summary now returns an object {blocks: [...], total_supply,
        // genesis_total, expected_total, accumulated_*}. Backward-compat note:
        // an array result (legacy server) is still accepted as the blocks list.
        json blocks = result.is_array() ? result : result.value("blocks", json::array());
        for (auto& b : blocks) {
            std::cout << "#" << std::setw(6) << std::left << b.value("index", uint64_t{0})
                      << " mode=" << b.value("consensus_mode", 0)
                      << " txs=" << std::setw(3) << std::left << b.value("tx_count", 0)
                      << " creators=" << b.value("creators", json::array()).dump()
                      << " hash=" << b.value("hash", std::string{}).substr(0, 12)
                      << "\n";
        }
        if (result.is_object()) {
            std::cout << "height=" << result.value("height", uint64_t{0})
                      << " total_supply=" << result.value("total_supply", uint64_t{0})
                      << " genesis_total=" << result.value("genesis_total", uint64_t{0})
                      << " (subsidy=+" << result.value("accumulated_subsidy", uint64_t{0})
                      << " inbound=+" << result.value("accumulated_inbound", uint64_t{0})
                      << " slashed=-" << result.value("accumulated_slashed", uint64_t{0})
                      << " outbound=-" << result.value("accumulated_outbound", uint64_t{0})
                      << ")\n";
        }
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ committee [--json] [--rpc-port N]
//   Print the current epoch's K-of-K committee (the creators producing
//   blocks right now). Pure function of chain state — deterministic
//   across all nodes on the same chain at the same height. Default
//   output is a human-readable table; --json emits the raw RPC array
//   verbatim, suitable for feeding directly into `verify-block-sigs
//   --committee` for light-client K-of-K signature verification.
static int cmd_committee(int argc, char** argv) {
    bool json_out = false;
    bool count_only = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if      (a == "--json")  json_out   = true;
        else if (a == "--count") count_only = true;
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "committee");
        // --count: bare integer (size of next-K committee). For
        // monitoring scripts in regional deployments where the
        // committee may temporarily be < K (region under-quorum).
        // Composes with --json to emit `{"count": N}` (single-line).
        if (count_only) {
            size_t n = result.is_array() ? result.size() : 0;
            if (json_out) std::cout << json({{"count", n}}).dump() << "\n";
            else          std::cout << n << "\n";
            return 0;
        }
        if (json_out) {
            std::cout << result.dump(2) << "\n";
            return 0;
        }
        if (!result.is_array() || result.empty()) {
            std::cout << "(empty committee — chain has no eligible validators yet)\n";
            return 0;
        }
        std::cout << std::left
                  << std::setw(25) << "domain"
                  << std::setw(10) << "stake"
                  << std::setw(15) << "active_from"
                  << "ed_pub\n";
        for (auto& v : result) {
            std::cout << std::setw(25) << v.value("domain", std::string{})
                      << std::setw(10) << v.value("stake", uint64_t{0})
                      << std::setw(15) << v.value("active_from", uint64_t{0})
                      << v.value("ed_pub", std::string{}).substr(0, 24) << "...\n";
        }
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ pending-params [--json] [--rpc-port N]
//   List PARAM_CHANGE entries that have been validated and staged but
//   not yet activated. Each entry shows (effective_height, name,
//   value_hex, value_bytes). Sorted ascending by effective_height; at
//   each block apply, entries with effective_height <= block.index
//   activate (the named field mutates) in insertion order.
//
//   A5 Phase 2 governance visibility primitive — useful for operators
//   in `governance_mode=1` deployments to confirm that PARAM_CHANGE
//   txs have been accepted, see what's about to land, and audit drift
//   between observed chain state and expected post-activation state.
// determ pending-params [--at-height N] [--json] [--rpc-port P]
//   List A5 PARAM_CHANGE entries staged but not yet activated.
//   --at-height N filters to entries with effective_height <= N
//                (i.e., what WILL have activated by block N). Useful
//                for operators verifying that a planned upgrade
//                window covers the expected param changes. Empty
//                result if no entries qualify (or no entries at all).
//   Default output: tabular; --json passes the filtered RPC array
//                   through verbatim.
static int cmd_pending_params(int argc, char** argv) {
    bool json_out = false;
    bool have_at_height = false;
    uint64_t at_height = 0;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json") json_out = true;
        else if (a == "--at-height" && i + 1 < argc) {
            have_at_height = true;
            if (!arg_u64("pending-params", "--at-height", argv[i + 1], at_height)) return 1;
        }
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "pending_params");
        if (!result.is_array()) result = json::array();

        // --at-height filtering: client-side post-filter on the RPC
        // result. Server returns the full list (ordered by
        // effective_height ascending); we just drop entries with
        // effective_height > at_height. Cheaper than a new RPC method
        // and keeps the server-side handler simple.
        if (have_at_height) {
            json filtered = json::array();
            for (auto& e : result) {
                uint64_t eff = e.value("effective_height", uint64_t{0});
                if (eff <= at_height) filtered.push_back(e);
            }
            result = std::move(filtered);
        }

        if (json_out) {
            std::cout << result.dump(2) << "\n";
            return 0;
        }
        if (result.empty()) {
            if (have_at_height) {
                std::cout << "(no PARAM_CHANGE entries with effective_height <= "
                          << at_height << ")\n";
            } else {
                std::cout << "(no pending PARAM_CHANGE entries)\n";
            }
            return 0;
        }
        std::cout << std::left
                  << std::setw(20) << "effective_height"
                  << std::setw(28) << "name"
                  << std::setw(8)  << "bytes"
                  << "value_hex (first 32 chars)\n";
        for (auto& e : result) {
            std::string hex = e.value("value_hex", std::string{});
            std::cout << std::setw(20) << e.value("effective_height", uint64_t{0})
                      << std::setw(28) << e.value("name", std::string{})
                      << std::setw(8)  << e.value("value_bytes", uint64_t{0})
                      << hex.substr(0, std::min<size_t>(hex.size(), 32))
                      << (hex.size() > 32 ? "..." : "")
                      << "\n";
        }
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ head [--field height|hash] [--json] [--rpc-port P]
//   Print just the chain's current head — height + head_hash on a
//   single line (space-separated by default). For monitoring scripts
//   tracking chain advancement:
//     while true; do read h hash <<< "$(determ head)"; echo "$h $hash"; sleep 1; done
//   --field height  prints just the height (no hash) — for `expr`-style scripts.
//   --field hash    prints just the hash (no height).
//   --json emits {height, head_hash} for scripts that want structured output.
//   Pulls from status RPC. Exit 1 if no chain loaded or --field value unknown.
static int cmd_head(int argc, char** argv) {
    bool json_out = false;
    std::string field;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json") json_out = true;
        else if (a == "--field" && i + 1 < argc) field = argv[i + 1];
    }
    if (!field.empty() && field != "height" && field != "hash") {
        std::cerr << "Error: --field must be 'height' or 'hash', got '"
                  << field << "'\n";
        return 1;
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "status");
        uint64_t height = result.value("height", uint64_t{0});
        std::string head_hash = result.value("head_hash", std::string{});
        if (head_hash.empty() && height == 0) {
            std::cerr << "Error: chain not loaded or empty\n";
            return 1;
        }
        if (json_out) {
            json out = {{"height", height}, {"head_hash", head_hash}};
            std::cout << out.dump() << "\n";
            return 0;
        }
        if (field == "height")     std::cout << height    << "\n";
        else if (field == "hash")  std::cout << head_hash << "\n";
        else                       std::cout << height << " " << head_hash << "\n";
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ block-hash <index> [--rpc-port P]
//   Print just the compute_hash of the block at the given index. The
//   `block` RPC returns full block JSON which already includes the
//   computed `hash` field. This CLI extracts and prints only that
//   value (no JSON envelope) for scripts that need to compare block
//   identity at a specific height across nodes:
//     a_hash=$(determ block-hash 100 --rpc-port 7778)
//     b_hash=$(determ block-hash 100 --rpc-port 7779)
//     [ "$a_hash" == "$b_hash" ] && echo "agree" || echo "FORKED"
//   Exit 1 if index out of range; exit 0 + 64-hex on success.
static int cmd_block_hash(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ block-hash <index> [--rpc-port N]\n";
        return 1;
    }
    uint64_t index = 0;
    if (!arg_u64("block-hash", "<index>", argv[0], index)) return 1;
    uint16_t port = get_rpc_port(argc, argv);
    try {
        json params = {{"index", index}};
        auto result = rpc::rpc_call("127.0.0.1", port, "block", params);
        if (result.is_null()) {
            std::cerr << "Error: block " << index
                      << " out of range (chain.height too low)\n";
            return 1;
        }
        std::string hash = result.value("hash", std::string{});
        if (hash.empty()) {
            std::cerr << "Error: block JSON missing 'hash' field\n";
            return 1;
        }
        std::cout << hash << "\n";
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ block-info <index> [--field NAME] [--json] [--rpc-port P]
//   Print one or more fields of a single block. Extension of
//   `block-hash` (which only emits compute_hash) to any block field:
//   index, prev_hash, timestamp, tx_root, state_root, block_hash,
//   consensus_mode.
//
//   --field NAME       Select which field to emit (default: full block
//                      JSON). Bare-value output for shell-script
//                      consumption.
//   --json             Emit the raw block JSON envelope (same as
//                      `block-hash`'s underlying `block` RPC response).
//
//   Without --field, defaults to printing the full block. With --field,
//   prints just the field value. Operator examples:
//
//     determ block-info 100 --field state_root --rpc-port 7778
//     # → 64-char hex state_root
//
//     determ block-info 100 --field timestamp
//     # → block timestamp as unsigned integer
//
//   Operator use cases: "what was state_root at block 100?" (audit
//   trail); "what was timestamp delta between blocks N and M?"
//   (chain progress velocity).
static int cmd_block_info(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ block-info <index> [--field NAME] "
                     "[--json] [--rpc-port N]\n";
        return 1;
    }
    uint64_t index = 0;
    try { index = std::stoull(argv[0]); }
    catch (...) {
        std::cerr << "Error: <index> must be an unsigned integer\n";
        return 1;
    }

    std::string field;
    bool json_out = false;
    for (int i = 1; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json") json_out = true;
        else if (a == "--field" && i + 1 < argc) field = argv[i + 1];
    }

    static const std::vector<std::string> kAllowedFields = {
        "index", "prev_hash", "timestamp", "tx_root",
        "state_root", "block_hash", "consensus_mode"
    };
    if (!field.empty()) {
        bool ok = false;
        for (const auto& f : kAllowedFields) if (f == field) { ok = true; break; }
        if (!ok) {
            std::cerr << "Error: unknown --field '" << field << "' — allowed: ";
            for (size_t i = 0; i < kAllowedFields.size(); ++i) {
                if (i) std::cerr << ", ";
                std::cerr << kAllowedFields[i];
            }
            std::cerr << "\n";
            return 1;
        }
    }

    uint16_t port = get_rpc_port(argc, argv);
    try {
        json params = {{"index", index}};
        auto result = rpc::rpc_call("127.0.0.1", port, "block", params);
        if (result.is_null()) {
            std::cerr << "Error: block " << index
                      << " out of range (chain.height too low)\n";
            return 1;
        }

        // block RPC returns full Block JSON. The block_hash field is
        // computed server-side and added (matches the `hash` field
        // emitted by Block::to_json post-compute_hash).
        // Aliases: block_hash and hash refer to the same value.
        if (!field.empty()) {
            // Map "block_hash" → "hash" for the block RPC's emitted field.
            std::string lookup = (field == "block_hash") ? "hash" : field;
            if (!result.contains(lookup) || result[lookup].is_null()) {
                std::cout << "\n";  // empty line for missing
                return 0;
            }
            const auto& v = result[lookup];
            if      (v.is_string())  std::cout << v.get<std::string>() << "\n";
            else if (v.is_number())  std::cout << v.dump()              << "\n";
            else if (v.is_boolean()) std::cout << (v.get<bool>() ? "true" : "false") << "\n";
            else                      std::cout << v.dump()              << "\n";
            return 0;
        }

        if (json_out) {
            std::cout << result.dump() << "\n";
        } else {
            std::cout << result.dump(2) << "\n";
        }
        return 0;
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
}

// determ block-range <from> <to> [--field NAME] [--json] [--rpc-port P]
//   Bulk-fetch a range of block fields via the headers RPC. Inclusive
//   on both ends ([from, to]). Builds on the existing `block-hash`
//   CLI (which fetches a single block at a time) — operators doing
//   fork detection across multiple heights pay one RPC + pagination
//   round trip per up-to-256 headers instead of one per height.
//
//   --field NAME selects which header field to emit per height.
//                Default: block_hash. Allowed: index, prev_hash,
//                state_root, block_hash, timestamp.
//   --json       emits the full headers-array JSON (machine-readable
//                envelope; same shape `determ headers` produces).
//
//   Default output: one line per height — `<index> <value>`. With
//   --field NAME, the format is one bare value per line (no index
//   prefix) — ready for diff(1) or comparison scripts:
//
//     $ determ block-range 100 105 --field block_hash --rpc-port 7778
//     <hash100>
//     <hash101>
//     ...
//
//   Each height that's out-of-range (server-side height < requested)
//   is omitted (the headers RPC truncates). Exit 1 only on RPC error
//   or invalid args; partial responses are an honest reflection of
//   chain state.
static int cmd_block_range(int argc, char** argv) {
    if (argc < 2) {
        std::cerr << "Usage: determ block-range <from> <to> "
                     "[--field NAME] [--json] [--rpc-port N]\n";
        return 1;
    }
    uint64_t from_idx = 0, to_idx = 0;
    try {
        from_idx = std::stoull(argv[0]);
        to_idx   = std::stoull(argv[1]);
    } catch (const std::exception& e) {
        std::cerr << "Error: <from> and <to> must be unsigned integers\n";
        return 1;
    }
    if (to_idx < from_idx) {
        std::cerr << "Error: <to> (" << to_idx << ") must be >= <from> ("
                  << from_idx << ")\n";
        return 1;
    }

    bool json_out = false;
    std::string field = "block_hash";
    for (int i = 2; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json") json_out = true;
        else if (a == "--field" && i + 1 < argc) field = argv[i + 1];
    }
    static const std::vector<std::string> kAllowedFields = {
        "index", "prev_hash", "state_root", "block_hash", "timestamp"
    };
    bool field_ok = false;
    for (const auto& f : kAllowedFields) if (f == field) { field_ok = true; break; }
    if (!field_ok) {
        std::cerr << "Error: unknown --field '" << field << "' — allowed: ";
        for (size_t i = 0; i < kAllowedFields.size(); ++i) {
            if (i) std::cerr << ", ";
            std::cerr << kAllowedFields[i];
        }
        std::cerr << "\n";
        return 1;
    }
    uint16_t port = get_rpc_port(argc, argv);

    constexpr uint32_t PAGE = 256;  // Mirrors HEADERS_PAGE_MAX server-side.
    json all = json::array();
    try {
        uint64_t cur = from_idx;
        while (cur <= to_idx) {
            uint64_t remaining = to_idx - cur + 1;
            uint32_t want = uint32_t(std::min<uint64_t>(remaining, PAGE));
            json params = {{"from", cur}, {"count", want}};
            auto result = rpc::rpc_call("127.0.0.1", port, "headers", params);
            if (!result.is_object() || !result.contains("headers")
                || !result["headers"].is_array()) {
                std::cerr << "Error: headers RPC returned unexpected shape\n";
                return 1;
            }
            const auto& hs = result["headers"];
            for (auto& h : hs) all.push_back(h);
            if (hs.empty() || hs.size() < want) break;  // server-side truncation
            cur += hs.size();
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }

    if (json_out) {
        std::cout << json({{"headers", all},
                              {"from", from_idx},
                              {"to", to_idx},
                              {"received", all.size()}}).dump() << "\n";
        return 0;
    }

    // Default: one line per header. If --field omitted (default
    // block_hash), prefix with index for readability; if --field set
    // explicitly, emit bare values for shell-script consumption.
    bool default_field = (field == "block_hash");
    for (auto& h : all) {
        if (!h.contains(field) || h[field].is_null()) {
            std::cout << "\n";  // honest missing-value marker
            continue;
        }
        const auto& v = h[field];
        if (default_field) {
            uint64_t idx = h.value("index", uint64_t{0});
            std::cout << idx << " " << v.get<std::string>() << "\n";
        } else if (v.is_string())   std::cout << v.get<std::string>() << "\n";
        else if (v.is_number())     std::cout << v.dump() << "\n";
        else                         std::cout << v.dump() << "\n";
    }
    return 0;
}

// determ chain-id [--rpc-port P]
//   Print just the chain's genesis-block hash — the canonical
//   chain-identity value. Monitoring scripts use this to compare
//   chain identity across deployments / nodes without parsing the
//   full status RPC. Pulls from `status` RPC (single integer call).
//   Output: 64-char hex (no newline-prefixed label). Exit 1 if the
//   chain hasn't loaded a genesis block yet.
static int cmd_chain_id(int argc, char** argv) {
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "status");
        std::string genesis_hash = result.value("genesis", std::string{});
        if (genesis_hash.empty()) {
            std::cerr << "Error: chain has no genesis block loaded\n";
            return 1;
        }
        std::cout << genesis_hash << "\n";
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ check-fork --node-a host:port --node-b host:port
//                   --from N --to M [--field state_root|block_hash]
//                   [--json]
//
//   Automated cross-node divergence detection. Fetches the requested
//   range of block fields from BOTH nodes (using the same paged headers
//   path that `block-range` uses internally) and reports the FIRST
//   height where the two disagree.
//
//   Real operator use: when two nodes report different `state_root` at
//   the same `height`, this command localizes the divergence to a
//   specific block — operators can then drill into that block's
//   `transactions` / `inbound_receipts` / `equivocation_events` to find
//   which event caused the fork.
//
//   Default field is `state_root` (the canonical chain-state commitment).
//   `block_hash` also valuable for "did headers diverge?" checks.
//
//   Exit codes:
//     0 — ranges identical OR one side truncated to a shorter set
//          (informational; not a test gate by default)
//     2 — DIVERGENCE detected; first-divergent height printed
//     1 — error (bad args, RPC error, unknown --field)
//
//   --json emits {"identical": <bool>, "first_divergence": <N>|null,
//                 "a": [...], "b": [...]} for machine consumers.
//
//   Example:
//     determ check-fork --node-a 127.0.0.1:7778 \
//                       --node-b 127.0.0.1:7779 \
//                       --from 100 --to 200 \
//                       --field state_root
static int cmd_check_fork(int argc, char** argv) {
    std::string node_a, node_b;
    std::string field = "state_root";
    uint64_t from_idx = 0, to_idx = 0;
    bool have_from = false, have_to = false;
    bool json_out = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if      (a == "--node-a" && i + 1 < argc) node_a = argv[i + 1];
        else if (a == "--node-b" && i + 1 < argc) node_b = argv[i + 1];
        else if (a == "--from"   && i + 1 < argc) {
            try { from_idx = std::stoull(argv[i + 1]); have_from = true; }
            catch (...) { std::cerr << "Error: --from must be unsigned\n"; return 1; }
        }
        else if (a == "--to"     && i + 1 < argc) {
            try { to_idx = std::stoull(argv[i + 1]); have_to = true; }
            catch (...) { std::cerr << "Error: --to must be unsigned\n"; return 1; }
        }
        else if (a == "--field"  && i + 1 < argc) field = argv[i + 1];
        else if (a == "--json")                    json_out = true;
    }
    if (node_a.empty() || node_b.empty() || !have_from || !have_to) {
        std::cerr << "Usage: determ check-fork --node-a host:port --node-b host:port "
                     "--from N --to M [--field state_root|block_hash] [--json]\n";
        return 1;
    }
    if (to_idx < from_idx) {
        std::cerr << "Error: --to (" << to_idx << ") must be >= --from ("
                  << from_idx << ")\n";
        return 1;
    }
    static const std::vector<std::string> kAllowedFields = {
        "index", "prev_hash", "state_root", "block_hash", "timestamp"
    };
    bool field_ok = false;
    for (const auto& f : kAllowedFields) if (f == field) { field_ok = true; break; }
    if (!field_ok) {
        std::cerr << "Error: unknown --field '" << field << "' — allowed: ";
        for (size_t i = 0; i < kAllowedFields.size(); ++i) {
            if (i) std::cerr << ", ";
            std::cerr << kAllowedFields[i];
        }
        std::cerr << "\n";
        return 1;
    }

    // Split "host:port" into (host, port) for rpc_call.
    auto split_addr = [](const std::string& addr) {
        size_t col = addr.find(':');
        if (col == std::string::npos)
            throw std::runtime_error("address must be host:port, got '" + addr + "'");
        return std::make_pair(addr.substr(0, col),
                              uint16_t(std::stoul(addr.substr(col + 1))));
    };

    // Bulk-fetch from one node using the same paged path as cmd_block_range.
    auto fetch_range = [&](const std::string& addr) -> json {
        auto [host, port] = split_addr(addr);
        constexpr uint32_t PAGE = 256;
        json all = json::array();
        uint64_t cur = from_idx;
        while (cur <= to_idx) {
            uint64_t remaining = to_idx - cur + 1;
            uint32_t want = uint32_t(std::min<uint64_t>(remaining, PAGE));
            json params = {{"from", cur}, {"count", want}};
            auto result = rpc::rpc_call(host, port, "headers", params);
            if (!result.is_object() || !result.contains("headers")
                || !result["headers"].is_array()) {
                throw std::runtime_error("headers RPC unexpected shape from " + addr);
            }
            const auto& hs = result["headers"];
            for (auto& h : hs) all.push_back(h);
            if (hs.empty() || hs.size() < want) break;  // truncated
            cur += hs.size();
        }
        return all;
    };

    json a_arr, b_arr;
    try {
        a_arr = fetch_range(node_a);
        b_arr = fetch_range(node_b);
    } catch (const std::exception& e) {
        if (json_out) {
            std::cout << json({{"error", "fetch_failed"},
                                  {"message", e.what()}}).dump() << "\n";
        } else {
            std::cerr << "Error: " << e.what() << "\n";
        }
        return 1;
    }

    // Find first divergence (compare common prefix only).
    size_t n_compare = std::min(a_arr.size(), b_arr.size());
    int64_t first_div = -1;
    for (size_t i = 0; i < n_compare; ++i) {
        std::string va = a_arr[i].value(field, std::string{});
        std::string vb = b_arr[i].value(field, std::string{});
        if (va != vb) {
            // Translate array index back to chain height (from_idx + i).
            first_div = int64_t(from_idx + i);
            break;
        }
    }
    bool identical = (first_div < 0);

    if (json_out) {
        json env = {
            {"identical",          identical},
            {"first_divergence",   identical ? json(nullptr) : json(first_div)},
            {"node_a_received",    a_arr.size()},
            {"node_b_received",    b_arr.size()},
            {"field",              field},
            {"from",               from_idx},
            {"to",                 to_idx}
        };
        std::cout << env.dump() << "\n";
    } else {
        if (identical) {
            std::cout << "check-fork: ranges agree on `" << field << "` "
                      << "(" << n_compare << " heights compared: "
                      << from_idx << " .. " << (from_idx + n_compare - 1) << ")\n";
            if (a_arr.size() != b_arr.size()) {
                std::cout << "  note: one node truncated — node-a returned "
                          << a_arr.size() << " headers, node-b returned "
                          << b_arr.size() << "\n";
            }
        } else {
            std::cout << "check-fork: FORK detected at height " << first_div
                      << " (field=" << field << ")\n";
            const auto& av = a_arr[first_div - from_idx][field];
            const auto& bv = b_arr[first_div - from_idx][field];
            std::cout << "  node-a (" << node_a << "): "
                      << (av.is_string() ? av.get<std::string>() : av.dump()) << "\n";
            std::cout << "  node-b (" << node_b << "): "
                      << (bv.is_string() ? bv.get<std::string>() : bv.dump()) << "\n";
        }
    }
    return identical ? 0 : 2;
}

// determ supply [--json] [--rpc-port P]
//   Compact A1 unitary-balance summary — genesis_total + the four
//   running counters (subsidy minted, inbound credited, slashed,
//   outbound) — and the expected vs live totals. Useful for monitoring
//   scripts that just want supply numbers without the chain-summary
//   block-by-block detail.
//
//   Output format:
//     genesis_total:        N
//     +accumulated_subsidy: N    (E1/E3/E4 mint history)
//     +accumulated_inbound: N    (cross-shard credits received)
//     -accumulated_slashed: N    (suspension + equivocation forfeits)
//     -accumulated_outbound: N   (cross-shard credits sent)
//     expected_total:       N    (= genesis + subsidy + inbound
//                                   - slashed - outbound)
//     live_total_supply:    N    (= Σ accounts.balance + Σ stakes.locked)
//     A1 invariant: OK | VIOLATED  (expected == live ?)
//
//   --json emits the same fields as a JSON object for scripts.
//   Pulls from chain_summary RPC (which already includes all
//   A1 counters) — no new RPC method needed.

// determ tx-summary [--last N] [--by-type] [--json] [--rpc-port P]
//   Per-type transaction count over the last N blocks (default 10).
//   Operator capacity-monitoring tool: "how many TRANSFERs vs STAKEs
//   vs DAPP_CALLs did we process in the last N blocks?" Useful for
//   dashboards tracking workload mix.
//
//   --last N        : window size (default 10, max bounded by chain-summary RPC)
//   --by-type       : emit per-type breakdown (default mode)
//   --json          : structured output for scripts
//                       {total: N, by_type: {TRANSFER: N, STAKE: N, ...},
//                        block_count: N, first_index: I, last_index: J}
//
//   Pulls from chain_summary RPC which already returns full block JSON
//   (including transactions[].type). No new RPC method needed.
//
//   Default human-readable output:
//     window:       blocks [I..J] (N blocks)
//     total:        T txs
//     by type:
//       TRANSFER:        N1
//       STAKE:           N2
//       ...
//   (zero-count types omitted from human output; --json includes them)

// determ tx-hash --in <tx.json> [--json]
//   Compute Transaction hash from a JSON file without submitting.
//
//   Reads a single Transaction-shaped JSON object (the same shape produced
//   by Transaction::to_json) from --in, runs Transaction::from_json +
//   compute_hash, and prints the 64-hex hash. Pure local computation —
//   no RPC, no daemon, no signing.
//
//   Use cases:
//     - Predict a tx's hash before calling submit_tx (e.g., to pre-stage
//       a status-tracker entry against the future hash).
//     - Verify that a sender-computed hash matches the canonical signing-
//       bytes-driven hash on the receiver side (interop sanity check).
//     - Debug signature failures by comparing the hash the wallet signed
//       against what Determ would compute from the same JSON shape.
//
//   --in   FILE   Read JSON from FILE (required).
//   --json        Emit {"hash": "<64hex>"} instead of bare hex.
//
//   Exit codes:
//     0 — success, hash printed
//     1 — missing/unreadable --in, malformed JSON, or from_json error
static int cmd_tx_hash(int argc, char** argv) {
    std::string in_path;
    bool json_out = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--in" && i + 1 < argc) in_path = argv[i + 1];
        else if (a == "--json") json_out = true;
    }
    if (in_path.empty()) {
        std::cerr << "Usage: determ tx-hash --in <tx.json> [--json]\n";
        return 1;
    }
    std::ifstream f(in_path);
    if (!f) {
        std::cerr << "Error: cannot open --in file: " << in_path << "\n";
        return 1;
    }
    json j;
    try {
        f >> j;
    } catch (const std::exception& e) {
        std::cerr << "Error: failed to parse JSON from " << in_path
                  << ": " << e.what() << "\n";
        return 1;
    }
    determ::chain::Transaction tx;
    try {
        tx = determ::chain::Transaction::from_json(j);
    } catch (const std::exception& e) {
        std::cerr << "Error: Transaction::from_json failed: " << e.what() << "\n";
        return 1;
    }
    auto hash = tx.compute_hash();
    std::string hash_hex = determ::to_hex(hash);
    if (json_out) {
        json env = {{"hash", hash_hex}};
        std::cout << env.dump() << "\n";
    } else {
        std::cout << hash_hex << "\n";
    }
    return 0;
}

static int cmd_tx_summary(int argc, char** argv) {
    uint32_t last_n = 10;
    bool json_out = false;
    bool by_type = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--last" && i + 1 < argc) {
            try { last_n = uint32_t(std::stoul(argv[i + 1])); }
            catch (...) { std::cerr << "Error: --last must be unsigned\n"; return 1; }
        }
        else if (a == "--by-type") by_type = true;
        else if (a == "--json")    json_out = true;
    }
    uint16_t port = get_rpc_port(argc, argv);

    try {
        json params = {{"last_n", last_n}};
        auto result = rpc::rpc_call("127.0.0.1", port, "chain_summary", params);
        if (!result.is_object() || !result.contains("blocks")
            || !result["blocks"].is_array()) {
            std::cerr << "Error: chain_summary returned unexpected shape\n";
            return 1;
        }
        const auto& blocks = result["blocks"];

        // Tally per-type. We use the TxType string form emitted by
        // chain_summary's block.to_json (e.g., "TRANSFER", "STAKE", ...).
        std::map<std::string, uint64_t> by_type_count;
        uint64_t total = 0;
        uint64_t first_index = UINT64_MAX, last_index = 0;
        size_t block_count = 0;
        for (auto& blk : blocks) {
            if (!blk.is_object()) continue;
            uint64_t idx = blk.value("index", uint64_t{0});
            if (idx < first_index) first_index = idx;
            if (idx > last_index)  last_index = idx;
            block_count++;
            if (!blk.contains("transactions") || !blk["transactions"].is_array())
                continue;
            for (auto& tx : blk["transactions"]) {
                if (!tx.is_object()) continue;
                // TxType may be string or numeric depending on serialization;
                // chain_summary uses string form per Block::to_json convention.
                std::string type_str;
                if (tx.contains("type")) {
                    if (tx["type"].is_string())  type_str = tx["type"].get<std::string>();
                    else if (tx["type"].is_number()) type_str = tx["type"].dump();
                    else                              type_str = "UNKNOWN";
                } else {
                    type_str = "UNKNOWN";
                }
                by_type_count[type_str]++;
                total++;
            }
        }
        if (block_count == 0) first_index = 0;  // empty window

        if (json_out) {
            json bt = json::object();
            for (const auto& [k, v] : by_type_count) bt[k] = v;
            json env = {
                {"total",        total},
                {"by_type",      bt},
                {"block_count",  block_count},
                {"first_index",  first_index},
                {"last_index",   last_index}
            };
            std::cout << env.dump() << "\n";
            return 0;
        }

        // Human-readable output
        if (block_count == 0) {
            std::cout << "tx-summary: no blocks in window (chain is empty?)\n";
            return 0;
        }
        std::cout << "window:    blocks [" << first_index << ".." << last_index
                  << "] (" << block_count << " block"
                  << (block_count == 1 ? "" : "s") << ")\n";
        std::cout << "total:     " << total << " tx"
                  << (total == 1 ? "" : "s") << "\n";
        // by-type breakdown — print whether explicitly requested or default
        if (by_type || !by_type) {  // always print breakdown in default mode
            std::cout << "by type:\n";
            if (by_type_count.empty()) {
                std::cout << "  (no transactions in window)\n";
            }
            for (const auto& [k, v] : by_type_count) {
                std::cout << "  " << std::left << std::setw(20) << k
                          << v << "\n";
            }
        }
        return 0;
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
}

static int cmd_supply(int argc, char** argv) {
    bool json_out = false;
    std::string field;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json") json_out = true;
        else if (a == "--field" && i + 1 < argc) field = argv[i + 1];
    }
    // --field is one-shot scalar extraction for shell scripts:
    //   live_total_supply | expected_total | genesis_total
    //   accumulated_subsidy | accumulated_inbound | accumulated_slashed
    //   accumulated_outbound | a1_invariant_ok
    // Bare value on stdout; exit 0 if field resolves, exit 1 if unknown
    // field name. --field mode does NOT exit-2 on A1 violation — the
    // a1_invariant_ok field already exposes that bit.
    static const std::vector<std::string> kAllowedFields = {
        "genesis_total", "accumulated_subsidy", "accumulated_inbound",
        "accumulated_slashed", "accumulated_outbound",
        "expected_total", "live_total_supply", "a1_invariant_ok"
    };
    if (!field.empty()) {
        bool ok = false;
        for (const auto& f : kAllowedFields) if (f == field) { ok = true; break; }
        if (!ok) {
            std::cerr << "Error: unknown --field '" << field << "' — allowed: ";
            for (size_t i = 0; i < kAllowedFields.size(); ++i) {
                if (i) std::cerr << ", ";
                std::cerr << kAllowedFields[i];
            }
            std::cerr << "\n";
            return 1;
        }
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        // chain_summary already exposes all 5 counters + total_supply
        // (= live_total_supply). last_n=1 keeps the response light;
        // we only need the counters from the envelope, not blocks.
        json params = {{"last_n", uint32_t{1}}};
        auto result = rpc::rpc_call("127.0.0.1", port, "chain_summary", params);
        if (!result.is_object()) {
            std::cerr << "Error: chain_summary returned non-object\n";
            return 1;
        }
        uint64_t genesis_total   = result.value("genesis_total",       uint64_t{0});
        uint64_t accum_subsidy   = result.value("accumulated_subsidy", uint64_t{0});
        uint64_t accum_inbound   = result.value("accumulated_inbound", uint64_t{0});
        uint64_t accum_slashed   = result.value("accumulated_slashed", uint64_t{0});
        uint64_t accum_outbound  = result.value("accumulated_outbound",uint64_t{0});
        uint64_t live_supply     = result.value("total_supply",        uint64_t{0});
        uint64_t expected =
            genesis_total + accum_subsidy + accum_inbound
            - accum_slashed - accum_outbound;
        bool invariant_ok = (expected == live_supply);

        if (!field.empty()) {
            // One-shot scalar print for shell scripts.
            if      (field == "genesis_total")        std::cout << genesis_total  << "\n";
            else if (field == "accumulated_subsidy")  std::cout << accum_subsidy  << "\n";
            else if (field == "accumulated_inbound")  std::cout << accum_inbound  << "\n";
            else if (field == "accumulated_slashed")  std::cout << accum_slashed  << "\n";
            else if (field == "accumulated_outbound") std::cout << accum_outbound << "\n";
            else if (field == "expected_total")       std::cout << expected       << "\n";
            else if (field == "live_total_supply")    std::cout << live_supply    << "\n";
            else if (field == "a1_invariant_ok")
                std::cout << (invariant_ok ? "true" : "false") << "\n";
            return 0;
        }

        if (json_out) {
            json out = {
                {"genesis_total",        genesis_total},
                {"accumulated_subsidy",  accum_subsidy},
                {"accumulated_inbound",  accum_inbound},
                {"accumulated_slashed",  accum_slashed},
                {"accumulated_outbound", accum_outbound},
                {"expected_total",       expected},
                {"live_total_supply",    live_supply},
                {"a1_invariant_ok",      invariant_ok}
            };
            std::cout << out.dump(2) << "\n";
            return invariant_ok ? 0 : 2;  // exit 2 on invariant violation
        }
        std::cout << "genesis_total:        " << genesis_total  << "\n"
                  << "+accumulated_subsidy: " << accum_subsidy  << "\n"
                  << "+accumulated_inbound: " << accum_inbound  << "\n"
                  << "-accumulated_slashed: " << accum_slashed  << "\n"
                  << "-accumulated_outbound: " << accum_outbound << "\n"
                  << "expected_total:       " << expected       << "\n"
                  << "live_total_supply:    " << live_supply    << "\n"
                  << "A1 invariant:         "
                  << (invariant_ok ? "OK" : "VIOLATED")
                  << "\n";
        return invariant_ok ? 0 : 2;  // exit 2 on invariant violation
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
}

// determ abort-records [--top N] [--json] [--rpc-port P]
//   List abort_records (the S-032 cache) — domains that have aborted
//   in Phase-1 along with their count + most recent block. Sorted by
//   count descending so the most-aborted (most-suspended) domains
//   come first. Useful for diagnosing committee instability, BFT-
//   escalation patterns, and which validators may need remediation.
//
//   --top N truncates output to the first N entries (default: all).
//   --json passes the RPC array through verbatim for scripts.
static int cmd_abort_records(int argc, char** argv) {
    bool json_out = false;
    bool have_top = false;
    size_t top_n = 0;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json") json_out = true;
        else if (a == "--top" && i + 1 < argc) {
            have_top = true;
            try { top_n = static_cast<size_t>(std::stoul(argv[i + 1])); }
            catch (...) { std::cerr << "abort-records: --top must be an integer\n"; return 1; }
        }
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "abort_records");
        if (!result.is_array()) result = json::array();

        // --top N client-side truncation. RPC always returns the full
        // (sorted) list — cheap because abort_records is bounded by
        // the registered-validator pool size (<= a few hundred typical).
        if (have_top && result.size() > top_n) {
            json truncated = json::array();
            for (size_t i = 0; i < top_n; ++i) truncated.push_back(result[i]);
            result = std::move(truncated);
        }

        if (json_out) {
            std::cout << result.dump(2) << "\n";
            return 0;
        }
        if (result.empty()) {
            std::cout << "(no abort records — no Phase-1 aborts on this chain)\n";
            return 0;
        }
        std::cout << std::left
                  << std::setw(28) << "domain"
                  << std::setw(10) << "count"
                  << "last_block\n";
        for (auto& e : result) {
            std::cout << std::setw(28) << e.value("domain", std::string{})
                      << std::setw(10) << e.value("count", uint64_t{0})
                      << e.value("last_block", uint64_t{0})
                      << "\n";
        }
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ show-account <address> [--rpc-port N]
//   Inspect on-chain state for an arbitrary address (registered domain or
//   anonymous bearer wallet). Prints balance, next nonce, and registry
//   info + stake when the address is a registered validator.
static int cmd_show_account(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ show-account <address> [--rpc-port N] [--json]\n";
        return 1;
    }
    std::string addr = argv[0];
    uint16_t port = get_rpc_port(argc, argv);
    bool json_out = false;
    for (int i = 0; i < argc; ++i) {
        if (std::string(argv[i]) == "--json") json_out = true;
    }
    try {
        json params = {{"address", addr}};
        auto result = rpc::rpc_call("127.0.0.1", port, "account", params);
        if (result.is_null()) {
            if (json_out) {
                std::cout << json::object().dump() << "\n";
            } else {
                std::cout << "(no on-chain state for " << addr << ")\n";
            }
            return 0;
        }
        if (json_out) {
            // Pass-through the RPC's JSON — scripts get the same shape
            // they'd get from a direct RPC call without the human-
            // readable formatting overhead.
            std::cout << result.dump() << "\n";
            return 0;
        }
        std::cout << "address      : " << result.value("address", std::string{}) << "\n";
        std::cout << "anonymous    : " << (result.value("is_anonymous", false) ? "yes" : "no") << "\n";
        std::cout << "balance      : " << result.value("balance", uint64_t{0}) << "\n";
        std::cout << "next_nonce   : " << result.value("next_nonce", uint64_t{0}) << "\n";
        std::cout << "stake        : " << result.value("stake", uint64_t{0}) << "\n";
        if (result.contains("registry") && !result["registry"].is_null()) {
            auto& r = result["registry"];
            std::cout << "registry     :\n";
            std::cout << "  ed_pub       : " << r.value("ed_pub", std::string{}) << "\n";
            std::cout << "  registered_at: " << r.value("registered_at", uint64_t{0}) << "\n";
            std::cout << "  active_from  : " << r.value("active_from", uint64_t{0}) << "\n";
            std::cout << "  inactive_from: " << r.value("inactive_from", uint64_t{0}) << "\n";
        } else {
            std::cout << "registry     : (not registered)\n";
        }
    } catch (std::exception& e) {
        if (json_out) {
            json err = {{"error", e.what()}};
            std::cout << err.dump() << "\n";
        } else {
            std::cerr << "Error: " << e.what() << "\n";
        }
        return 1;
    }
    return 0;
}

// determ where-is <address|domain> --shard-count N [--salt-hex HEX]
//                                  [--json]
//
//   Local-only shard-routing diagnostic. Given an address (anon-form
//   `0x...64hex`) or a registered domain name, compute which shard it
//   routes to via `crypto::shard_id_for_address(addr, shard_count,
//   salt)`.
//
//   Operator use cases:
//     - "Which shard does this anon address live on?" — for incident
//       analysis ("why is this balance not showing up on shard 2?")
//     - "What shards do my faucet addresses route to?" — for capacity
//       planning ("are my pre-mine recipients balanced across shards?")
//
//   Inputs:
//     <address|domain>   positional, required. Anon-address (0x + 64
//                        hex) or registered domain string.
//     --shard-count N    REQUIRED. The deployment's configured shard
//                        count (from genesis `initial_shard_count`).
//     --salt-hex HEX     OPTIONAL. 64-hex shard_address_salt (from
//                        genesis). Defaults to zero salt if omitted —
//                        works for testnets / dev deployments that
//                        don't customize the salt.
//
//   Default output: `<address> -> shard <N> (of <shard-count>)`.
//   --json emits `{"address": "<>", "shard": N, "shard_count": N}`.
//
//   Pure local computation — no RPC required. Exit 1 on argument
//   error; exit 0 on successful routing.
static int cmd_where_is(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ where-is <address|domain> "
                     "--shard-count N [--salt-hex HEX] [--json]\n";
        return 1;
    }
    std::string address = argv[0];
    uint32_t shard_count = 0;
    bool have_shard_count = false;
    std::string salt_hex;
    bool json_out = false;

    for (int i = 1; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--shard-count" && i + 1 < argc) {
            try { shard_count = uint32_t(std::stoul(argv[i + 1])); have_shard_count = true; }
            catch (...) { std::cerr << "Error: --shard-count must be unsigned\n"; return 1; }
        }
        else if (a == "--salt-hex" && i + 1 < argc) salt_hex = argv[i + 1];
        else if (a == "--json") json_out = true;
    }
    if (!have_shard_count) {
        std::cerr << "Error: --shard-count is required\n";
        return 1;
    }
    if (shard_count == 0) {
        std::cerr << "Error: --shard-count must be > 0\n";
        return 1;
    }

    // Parse salt (default zero).
    Hash salt{};
    if (!salt_hex.empty()) {
        if (salt_hex.size() != 64) {
            std::cerr << "Error: --salt-hex must be 64 hex chars (got "
                      << salt_hex.size() << ")\n";
            return 1;
        }
        try {
            salt = from_hex_arr<32>(salt_hex);
        } catch (const std::exception& e) {
            std::cerr << "Error: invalid --salt-hex: " << e.what() << "\n";
            return 1;
        }
    }

    // Compute shard routing.
    ShardId shard_id;
    try {
        shard_id = crypto::shard_id_for_address(address, shard_count, salt);
    } catch (const std::exception& e) {
        std::cerr << "Error: routing failed: " << e.what() << "\n";
        return 1;
    }

    if (json_out) {
        std::cout << json({
            {"address",     address},
            {"shard",       static_cast<uint64_t>(shard_id)},
            {"shard_count", shard_count}
        }).dump() << "\n";
    } else {
        std::cout << address << " -> shard " << shard_id
                  << " (of " << shard_count << ")\n";
    }
    return 0;
}

// determ snapshot create [--out file.json] [--headers N] [--rpc-port N]
//   B6.basic: dump chain state (accounts, stakes, registrants, dedup,
//   tail headers) to a file. Operators host this for fast-bootstrap of
//   new nodes — restoring from a snapshot avoids replaying every block
//   from genesis. The result is JSON; a typical snapshot for a mature
//   chain is much smaller than the full chain.json. v1 verification
//   model: trust the source + post-restore consistency check (replay
//   the next handful of blocks); v2 adds state roots in the block
//   format for cryptographic verification.
static int cmd_snapshot_create(int argc, char** argv) {
    std::string out_path;
    uint32_t    header_count = 16;
    for (int i = 0; i < argc - 1; ++i) {
        std::string a = argv[i];
        if (a == "--out")     out_path = argv[i + 1];
        if (a == "--headers") { if (!arg_u32("snapshot create", "--headers", argv[i + 1], header_count)) return 1; }
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        json params = {{"headers", header_count}};
        auto result = rpc::rpc_call("127.0.0.1", port, "snapshot", params);
        std::string text = result.dump(2);
        if (out_path.empty()) {
            std::cout << text << "\n";
        } else {
            std::ofstream f(out_path);
            if (!f) { std::cerr << "Cannot write " << out_path << "\n"; return 1; }
            f << text << "\n";
            std::cout << "Snapshot written to " << out_path << "\n";
            std::cout << "  block_index : "
                      << result.value("block_index", uint64_t{0}) << "\n";
            std::cout << "  head_hash   : "
                      << result.value("head_hash", std::string{}) << "\n";
            std::cout << "  accounts    : "
                      << result.value("accounts", json::array()).size() << "\n";
            std::cout << "  stakes      : "
                      << result.value("stakes", json::array()).size() << "\n";
            std::cout << "  registrants : "
                      << result.value("registrants", json::array()).size() << "\n";
            std::cout << "  headers     : "
                      << result.value("headers", json::array()).size() << "\n";
        }
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

// determ snapshot fetch --peer host:port --out file.json [--headers N]
//   B6.basic: connect to a running node, send a SNAPSHOT_REQUEST over
//   the gossip-wire protocol, write the response to a file. Pure
//   network client; no genesis or chain config needed locally. After
//   fetch, validates by round-tripping through restore_from_snapshot
//   (head_hash sanity check). Operator workflow:
//     determ snapshot fetch --peer 1.2.3.4:7771 --out snap.json
//     # ... edit config to set snapshot_path = snap.json ...
//     determ start
static int cmd_snapshot_fetch(int argc, char** argv) {
    std::string peer_str, out_path;
    uint32_t header_count = 16;
    for (int i = 0; i < argc - 1; ++i) {
        std::string a = argv[i];
        if (a == "--peer")    peer_str    = argv[i + 1];
        if (a == "--out")     out_path    = argv[i + 1];
        if (a == "--headers") { if (!arg_u32("snapshot fetch", "--headers", argv[i + 1], header_count)) return 1; }
    }
    if (peer_str.empty() || out_path.empty()) {
        std::cerr << "Usage: determ snapshot fetch --peer host:port "
                     "--out file.json [--headers N]\n";
        return 1;
    }
    auto colon = peer_str.find(':');
    if (colon == std::string::npos) {
        std::cerr << "peer must be host:port\n";
        return 1;
    }
    std::string host = peer_str.substr(0, colon);
    uint16_t    port = static_cast<uint16_t>(std::stoi(peer_str.substr(colon + 1)));

    try {
        net::SyncClient client;
        client.connect(host, port);

        auto write_msg = [&](const net::Message& msg) {
            auto buf = msg.serialize();
            client.write_all(buf.data(), buf.size());
        };

        // HELLO so the peer doesn't drop us. We tag ourselves as
        // SINGLE/0 — bootstrap clients don't claim a chain identity.
        write_msg(net::make_hello("snapshot-fetcher", 0,
                                    ChainRole::SINGLE, 0));
        write_msg(net::make_snapshot_request(header_count));

        // Read framed messages until SNAPSHOT_RESPONSE arrives. Skip
        // any others (peer might gossip blocks/headers in the
        // meantime).
        std::array<uint8_t, 4> hdr;
        for (int spin = 0; spin < 200; ++spin) {
            client.read_exact(hdr.data(), hdr.size());
            uint32_t len = (uint32_t(hdr[0]) << 24)
                         | (uint32_t(hdr[1]) << 16)
                         | (uint32_t(hdr[2]) << 8)
                         |  uint32_t(hdr[3]);
            if (len == 0 || len > 16 * 1024 * 1024) {
                std::cerr << "fetch: bad frame length " << len << "\n";
                return 1;
            }
            std::vector<uint8_t> body(len);
            client.read_exact(body.data(), body.size());
            net::Message m = net::Message::deserialize(body.data(), body.size());
            if (m.type != net::MsgType::SNAPSHOT_RESPONSE) continue;

            // Validate by round-trip through restore_from_snapshot.
            chain::Chain c = chain::Chain::restore_from_snapshot(m.payload);
            std::ofstream f(out_path);
            if (!f) { std::cerr << "Cannot write " << out_path << "\n"; return 1; }
            f << m.payload.dump(2) << "\n";
            std::cout << "Snapshot fetched from " << peer_str << "\n";
            std::cout << "  block_index : " << (c.empty() ? 0 : c.head().index) << "\n";
            std::cout << "  head_hash   : "
                      << (c.empty() ? std::string{} : to_hex(c.head_hash())) << "\n";
            std::cout << "  accounts    : " << c.accounts().size()    << "\n";
            std::cout << "  stakes      : " << c.stakes().size()      << "\n";
            std::cout << "  registrants : " << c.registrants().size() << "\n";
            std::cout << "  written to  : " << out_path << "\n";
            return 0;
        }
        std::cerr << "fetch: timed out waiting for SNAPSHOT_RESPONSE\n";
        return 1;
    } catch (std::exception& e) {
        std::cerr << "fetch error: " << e.what() << "\n";
        return 1;
    }
}

// determ snapshot inspect --in file.json [--state-root <hex64>]
//   Round-trips a snapshot through Chain::restore_from_snapshot and
//   prints a human-readable summary. Validates JSON format, version,
//   head_hash consistency, AND post-restore state_root (S-033 + S-038
//   gates: restore_from_snapshot already rejects on mismatch). Useful
//   before staging a snapshot for fast-bootstrap of a new node.
//
//   Optional --state-root <hex64>: pin an externally-trusted state
//   root. Inspection succeeds only if the snapshot's tail-head
//   state_root matches. This is the trustless-fast-sync gate from a
//   light-client POV: a client that has verified the head's state
//   commitment via header-sync can use this to confirm a snapshot it
//   downloaded matches that commitment, with zero trust in the
//   snapshot's origin (S-033 + S-038 closure path; complements
//   `determ verify-state-proof` for per-field queries).
static int cmd_snapshot_inspect(int argc, char** argv) {
    std::string in_path;
    std::string expected_state_root_hex;
    bool json_out = false;
    for (int i = 0; i < argc - 1; ++i) {
        if (std::string(argv[i]) == "--in")          in_path = argv[i + 1];
        else if (std::string(argv[i]) == "--state-root") expected_state_root_hex = argv[i + 1];
    }
    // `--json` is a flag, not a value-pair, so scan all args including
    // the last position.
    for (int i = 0; i < argc; ++i) {
        if (std::string(argv[i]) == "--json") json_out = true;
    }
    if (in_path.empty()) {
        std::cerr << "Usage: determ snapshot inspect --in <file> "
                     "[--state-root <hex64>] [--json]\n";
        return 1;
    }
    try {
        std::ifstream f(in_path);
        if (!f) {
            if (json_out) {
                json err = {{"error", "cannot_open"}, {"path", in_path}};
                std::cout << err.dump() << "\n";
            } else {
                std::cerr << "Cannot open " << in_path << "\n";
            }
            return 1;
        }
        json snap = json::parse(f);
        chain::Chain c = chain::Chain::restore_from_snapshot(snap);

        // Compute the snapshot's restored state_root for display +
        // optional comparison against an externally-trusted root.
        // restore_from_snapshot already verified the snapshot-stored
        // state_root matches the recomputed one (S-033 + S-038 gate);
        // this is the read-out + the external-pin comparison.
        Hash restored_root = c.compute_state_root();

        // Build the inspection result. Same data in both formats; the
        // `--json` mode is for scripts that want to consume the result
        // (e.g., bootstrap-orchestrators that pipeline snapshot
        // verification + state-root checks).
        json result = {
            {"status",        "ok"},
            {"path",          in_path},
            {"block_index",   c.empty() ? 0 : c.head().index},
            {"head_hash",     c.empty() ? std::string{} : to_hex(c.head_hash())},
            {"state_root",    to_hex(restored_root)},
            {"accounts",      c.accounts().size()},
            {"stakes",        c.stakes().size()},
            {"registrants",   c.registrants().size()},
            {"block_subsidy", c.block_subsidy()},
            {"min_stake",     c.min_stake()},
            {"shard_count",   c.shard_count()},
            {"shard_id",      c.my_shard_id()},
            {"tail_headers",  c.height()},
        };

        // External-trusted-root pin (trustless-fast-sync gate).
        if (!expected_state_root_hex.empty()) {
            if (expected_state_root_hex.size() != 64) {
                if (json_out) {
                    json err = {
                        {"error", "invalid_state_root_length"},
                        {"got",   expected_state_root_hex.size()}
                    };
                    std::cout << err.dump() << "\n";
                } else {
                    std::cerr << "Error: --state-root must be 64 hex chars "
                                 "(32 bytes), got "
                              << expected_state_root_hex.size() << "\n";
                }
                return 1;
            }
            Hash expected = from_hex_arr<32>(expected_state_root_hex);
            if (expected != restored_root) {
                if (json_out) {
                    json err = {
                        {"error",                  "state_root_mismatch"},
                        {"snapshot_state_root",    to_hex(restored_root)},
                        {"supplied_state_root",    to_hex(expected)}
                    };
                    std::cout << err.dump() << "\n";
                } else {
                    std::cerr << "FAIL: snapshot state_root does NOT match "
                                 "supplied --state-root\n";
                    std::cerr << "  snapshot's state_root: "
                              << to_hex(restored_root) << "\n";
                    std::cerr << "  supplied state_root:   "
                              << to_hex(expected) << "\n";
                    std::cerr << "  (snapshot may have been tampered with, "
                                 "or was produced against a different chain "
                                 "than the one you trust)\n";
                }
                return 1;
            }
            result["trusted_root_match"] = true;
        }

        if (json_out) {
            std::cout << result.dump() << "\n";
        } else {
            std::cout << "snapshot OK: " << in_path << "\n";
            std::cout << "  block_index : " << result["block_index"].get<uint64_t>() << "\n";
            std::cout << "  head_hash   : " << result["head_hash"].get<std::string>() << "\n";
            std::cout << "  state_root  : " << result["state_root"].get<std::string>() << "\n";
            std::cout << "  accounts    : " << result["accounts"].get<size_t>()    << "\n";
            std::cout << "  stakes      : " << result["stakes"].get<size_t>()      << "\n";
            std::cout << "  registrants : " << result["registrants"].get<size_t>() << "\n";
            std::cout << "  block_subsidy: " << result["block_subsidy"].get<uint64_t>() << "\n";
            std::cout << "  min_stake   : " << result["min_stake"].get<uint64_t>() << "\n";
            std::cout << "  shard_count : " << result["shard_count"].get<uint32_t>() << "\n";
            std::cout << "  shard_id    : " << result["shard_id"].get<uint32_t>() << "\n";
            std::cout << "  tail headers: " << result["tail_headers"].get<size_t>() << "\n";
            if (result.contains("trusted_root_match"))
                std::cout << "  trusted root: ✓ matches --state-root\n";
        }
    } catch (std::exception& e) {
        if (json_out) {
            json err = {{"error", "exception"}, {"message", e.what()}};
            std::cout << err.dump() << "\n";
        } else {
            std::cerr << "Error: " << e.what() << "\n";
        }
        return 1;
    }
    return 0;
}

// determ snapshot diff <file-a> <file-b> [--json]
//   Compare two snapshots and print a divergence summary. Operator
//   tool for incident analysis: if two nodes report mismatched
//   state_root at the same height, an operator can grab a snapshot
//   from each and run this command to localize the divergence to
//   one of:
//     - block_index / head_hash / state_root
//     - account count or aggregate balance
//     - registry count
//     - stake count or aggregate stake
//     - one or more A1 unitary-supply counters
//
//   Both snapshots are validated through Chain::restore_from_snapshot
//   (so a malformed input fails fast); pure read-only comparison after.
//
//   Default output: human-readable. Each diff is a line "FIELD: A != B".
//   Identical snapshots print "(identical)" + exit 0. Differences exit 0
//   too (diff is informational; not a test gate). Errors exit 1.
//
//   --json emits a structured envelope:
//     {
//       "a": "<path>", "b": "<path>",
//       "identical": <bool>,
//       "differences": [{"field": "<name>", "a": <val>, "b": <val>}, ...]
//     }
//   Empty `differences` array when identical.
static int cmd_snapshot_diff(int argc, char** argv) {
    bool json_out = false;
    std::string path_a, path_b;
    // Scan args: 2 positional paths + optional --json flag.
    int pos = 0;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json") { json_out = true; continue; }
        if (pos == 0)      { path_a = a; pos++; }
        else if (pos == 1) { path_b = a; pos++; }
    }
    if (path_a.empty() || path_b.empty()) {
        std::cerr << "Usage: determ snapshot diff <file-a> <file-b> [--json]\n";
        return 1;
    }

    auto load = [&](const std::string& path) {
        std::ifstream f(path);
        if (!f) throw std::runtime_error("cannot open " + path);
        json snap = json::parse(f);
        return chain::Chain::restore_from_snapshot(snap);
    };

    chain::Chain ca, cb;
    try {
        ca = load(path_a);
        cb = load(path_b);
    } catch (const std::exception& e) {
        if (json_out) {
            json err = {{"error", "load_failed"}, {"message", e.what()}};
            std::cout << err.dump() << "\n";
        } else {
            std::cerr << "Error loading snapshot: " << e.what() << "\n";
        }
        return 1;
    }

    // Compute aggregates.
    auto agg = [](const chain::Chain& c) {
        struct A { uint64_t accounts, registrants, stakes, balance_sum, stake_sum; };
        A a{};
        a.accounts    = c.accounts().size();
        a.registrants = c.registrants().size();
        a.stakes      = c.stakes().size();
        for (auto& [_, ac] : c.accounts()) a.balance_sum += ac.balance;
        for (auto& [_, sk] : c.stakes())   a.stake_sum   += sk.locked;
        return a;
    };
    auto aa = agg(ca);
    auto ab = agg(cb);

    // Build the diffs list.
    json diffs = json::array();
    auto push_diff_u64 = [&](const char* field, uint64_t va, uint64_t vb) {
        if (va != vb) diffs.push_back({{"field", field}, {"a", va}, {"b", vb}});
    };
    auto push_diff_str = [&](const char* field, const std::string& va,
                              const std::string& vb) {
        if (va != vb) diffs.push_back({{"field", field}, {"a", va}, {"b", vb}});
    };
    push_diff_u64("block_index",
                  ca.empty() ? 0 : ca.head().index,
                  cb.empty() ? 0 : cb.head().index);
    push_diff_str("head_hash",
                  ca.empty() ? std::string{} : to_hex(ca.head_hash()),
                  cb.empty() ? std::string{} : to_hex(cb.head_hash()));
    push_diff_str("state_root",
                  to_hex(ca.compute_state_root()),
                  to_hex(cb.compute_state_root()));
    push_diff_u64("accounts",        aa.accounts,    ab.accounts);
    push_diff_u64("balance_sum",     aa.balance_sum, ab.balance_sum);
    push_diff_u64("registrants",     aa.registrants, ab.registrants);
    push_diff_u64("stakes",          aa.stakes,      ab.stakes);
    push_diff_u64("stake_sum",       aa.stake_sum,   ab.stake_sum);
    push_diff_u64("genesis_total",        ca.genesis_total(),        cb.genesis_total());
    push_diff_u64("accumulated_subsidy",  ca.accumulated_subsidy(),  cb.accumulated_subsidy());
    push_diff_u64("accumulated_inbound",  ca.accumulated_inbound(),  cb.accumulated_inbound());
    push_diff_u64("accumulated_slashed",  ca.accumulated_slashed(),  cb.accumulated_slashed());
    push_diff_u64("accumulated_outbound", ca.accumulated_outbound(), cb.accumulated_outbound());
    push_diff_u64("live_total_supply",    ca.live_total_supply(),    cb.live_total_supply());
    push_diff_u64("block_subsidy",   ca.block_subsidy(),   cb.block_subsidy());
    push_diff_u64("min_stake",       ca.min_stake(),       cb.min_stake());

    bool identical = diffs.empty();
    if (json_out) {
        json env = {
            {"a", path_a}, {"b", path_b},
            {"identical", identical},
            {"differences", diffs}
        };
        std::cout << env.dump() << "\n";
    } else {
        if (identical) {
            std::cout << "(identical)\n";
        } else {
            std::cout << "snapshot diff: " << path_a << " vs " << path_b << "\n";
            for (auto& d : diffs) {
                std::cout << "  " << d["field"].get<std::string>() << ": "
                          << d["a"].dump() << " != " << d["b"].dump() << "\n";
            }
        }
    }
    return 0;
}

// determ snapshot stats <file> [--json]
//   Lightweight metadata-only snapshot inspection — reads top-level
//   JSON fields without running the full Chain::restore_from_snapshot
//   pipeline. Useful for fast triage on large snapshot files before
//   committing to the heavy restore + state_root verify path.
//
//   Reports: file size on disk, version, block_index + head_hash from
//   the snapshot header, account/stake/registrant count, and the 5
//   A1 unitary-supply counters.
//
//   Default output: human-readable column. --json emits a structured
//   envelope:
//     {file, size_bytes, version, block_index, head_hash,
//      accounts, stakes, registrants,
//      genesis_total, accumulated_subsidy, accumulated_inbound,
//      accumulated_slashed, accumulated_outbound}
//
//   Differences from `snapshot inspect`:
//     - stats: O(parse + top-level field read) — fast even on 100 MB+
//     - inspect: O(parse + full restore + state_root compute) — slower
//                but verifies S-033/S-038 internal consistency
//
//   Exit 0 on success; exit 1 on file open / JSON parse / missing
//   field error.
static int cmd_snapshot_stats(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ snapshot stats <file> [--json]\n";
        return 1;
    }
    std::string path = argv[0];
    bool json_out = false;
    for (int i = 1; i < argc; ++i) {
        if (std::string(argv[i]) == "--json") json_out = true;
    }

    namespace fs = std::filesystem;
    std::error_code ec;
    uint64_t size_bytes = uint64_t(fs::file_size(path, ec));
    if (ec) {
        if (json_out) {
            std::cout << json({{"error", "cannot_open"}, {"path", path}}).dump() << "\n";
        } else {
            std::cerr << "Error: cannot open " << path << ": " << ec.message() << "\n";
        }
        return 1;
    }

    json snap;
    try {
        std::ifstream f(path);
        snap = json::parse(f);
    } catch (const std::exception& e) {
        if (json_out) {
            std::cout << json({{"error", "json_parse"}, {"message", e.what()}}).dump() << "\n";
        } else {
            std::cerr << "Error: JSON parse failed: " << e.what() << "\n";
        }
        return 1;
    }
    if (!snap.is_object()) {
        if (json_out) {
            std::cout << json({{"error", "not_object"}}).dump() << "\n";
        } else {
            std::cerr << "Error: snapshot is not a JSON object\n";
        }
        return 1;
    }

    // Top-level field reads. Use defensive .value() defaults — stats
    // is meant to work even on partial / older snapshot formats
    // (whereas `snapshot inspect` enforces strict version=1).
    int version              = snap.value("version", 0);
    uint64_t block_index     = snap.value("block_index", uint64_t{0});
    std::string head_hash    = snap.value("head_hash", std::string{});
    size_t accounts          = snap.contains("accounts")
                                  ? (snap["accounts"].is_array()
                                         ? snap["accounts"].size() : 0)
                                  : 0;
    size_t stakes            = snap.contains("stakes")
                                  ? (snap["stakes"].is_array()
                                         ? snap["stakes"].size() : 0)
                                  : 0;
    size_t registrants       = snap.contains("registrants")
                                  ? (snap["registrants"].is_array()
                                         ? snap["registrants"].size() : 0)
                                  : 0;
    uint64_t genesis_total   = snap.value("genesis_total",       uint64_t{0});
    uint64_t accum_subsidy   = snap.value("accumulated_subsidy", uint64_t{0});
    uint64_t accum_inbound   = snap.value("accumulated_inbound", uint64_t{0});
    uint64_t accum_slashed   = snap.value("accumulated_slashed", uint64_t{0});
    uint64_t accum_outbound  = snap.value("accumulated_outbound",uint64_t{0});

    if (json_out) {
        json env = {
            {"file",                path},
            {"size_bytes",          size_bytes},
            {"version",             version},
            {"block_index",         block_index},
            {"head_hash",           head_hash},
            {"accounts",            accounts},
            {"stakes",              stakes},
            {"registrants",         registrants},
            {"genesis_total",       genesis_total},
            {"accumulated_subsidy", accum_subsidy},
            {"accumulated_inbound", accum_inbound},
            {"accumulated_slashed", accum_slashed},
            {"accumulated_outbound",accum_outbound}
        };
        std::cout << env.dump() << "\n";
        return 0;
    }

    auto truncate = [](const std::string& s) {
        return s.size() > 24 ? s.substr(0, 24) + "..." : s;
    };
    std::cout << "file         : " << path        << "\n"
              << "size_bytes   : " << size_bytes  << "\n"
              << "version      : " << version     << "\n"
              << "block_index  : " << block_index << "\n"
              << "head_hash    : " << truncate(head_hash) << "\n"
              << "accounts     : " << accounts    << "\n"
              << "stakes       : " << stakes      << "\n"
              << "registrants  : " << registrants << "\n"
              << "A1 counters:\n"
              << "  genesis_total       : " << genesis_total  << "\n"
              << "  accumulated_subsidy : " << accum_subsidy  << "\n"
              << "  accumulated_inbound : " << accum_inbound  << "\n"
              << "  accumulated_slashed : " << accum_slashed  << "\n"
              << "  accumulated_outbound: " << accum_outbound << "\n";
    return 0;
}

static int cmd_snapshot(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ snapshot {create|inspect|fetch|diff|stats} ...\n";
        return 1;
    }
    std::string sub = argv[0];
    if (sub == "create")  return cmd_snapshot_create (argc - 1, argv + 1);
    if (sub == "inspect") return cmd_snapshot_inspect(argc - 1, argv + 1);
    if (sub == "fetch")   return cmd_snapshot_fetch  (argc - 1, argv + 1);
    if (sub == "diff")    return cmd_snapshot_diff   (argc - 1, argv + 1);
    if (sub == "stats")   return cmd_snapshot_stats  (argc - 1, argv + 1);
    std::cerr << "Unknown snapshot subcommand: " << sub << "\n";
    return 1;
}

// determ show-tx <hash> [--rpc-port N] [--json]
//   Look up a transaction by its hex-encoded hash. Reports the tx
//   payload, the block it landed in, and the block's timestamp.
//   --json emits the raw RPC envelope for script consumption.
static int cmd_show_tx(int argc, char** argv) {
    if (argc < 1) {
        std::cerr << "Usage: determ show-tx <hash> [--rpc-port N] [--json]\n";
        return 1;
    }
    std::string hash_hex = argv[0];
    uint16_t port = get_rpc_port(argc, argv);
    bool json_out = false;
    for (int i = 0; i < argc; ++i) {
        if (std::string(argv[i]) == "--json") json_out = true;
    }
    try {
        json params = {{"hash", hash_hex}};
        auto result = rpc::rpc_call("127.0.0.1", port, "tx", params);
        if (result.is_null()) {
            if (json_out) {
                std::cout << json::object().dump() << "\n";
            } else {
                std::cout << "(tx " << hash_hex.substr(0, 16) << "... not found in any finalized block)\n";
            }
            return 0;
        }
        if (json_out) {
            std::cout << result.dump() << "\n";
            return 0;
        }
        std::cout << "block_index : " << result.value("block_index", uint64_t{0}) << "\n";
        std::cout << "block_hash  : " << result.value("block_hash", std::string{}) << "\n";
        std::cout << "timestamp   : " << result.value("timestamp", int64_t{0}) << "\n";
        std::cout << "transaction :\n";
        std::cout << result["tx"].dump(2) << "\n";
    } catch (std::exception& e) {
        if (json_out) {
            json err = {{"error", e.what()}};
            std::cout << err.dump() << "\n";
        } else {
            std::cerr << "Error: " << e.what() << "\n";
        }
        return 1;
    }
    return 0;
}

// determ peers [--json] [--rpc-port N]
//   List connected peers. Default: one host:port per line. --json
//   emits the raw RPC array verbatim (one JSON array of strings).
static int cmd_peers(int argc, char** argv) {
    bool json_out = false;
    bool count_only = false;
    for (int i = 0; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "--json")       json_out   = true;
        else if (a == "--count") count_only = true;
    }
    uint16_t port = get_rpc_port(argc, argv);
    try {
        auto result = rpc::rpc_call("127.0.0.1", port, "peers");
        // --count: bare integer (count of connected peers) for shell
        // scripts. Result MUST be an array; degenerate non-array values
        // print 0 (so a malformed RPC response can't crash monitoring
        // dashboards). --count and --json compose: --count + --json
        // emits `{"count": N}` (single-line, machine-readable).
        if (count_only) {
            size_t n = result.is_array() ? result.size() : 0;
            if (json_out) std::cout << json({{"count", n}}).dump() << "\n";
            else          std::cout << n << "\n";
            return 0;
        }
        if (json_out) {
            std::cout << result.dump(2) << "\n";
            return 0;
        }
        if (result.empty()) { std::cout << "(no peers connected)\n"; return 0; }
        for (auto& p : result) std::cout << "  " << p.get<std::string>() << "\n";
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
        return 1;
    }
    return 0;
}

